module fir_filter (
    input logic clk,                 // Clock signal
    input logic reset,               // Reset signal
    input logic signed [15:0] input_sample,  // Input data sample
    output logic signed [15:0] output_sample, // Output filtered sample
    input logic signed [15:0] coeff0, // Coefficient for current input sample
    input logic signed [15:0] coeff1, // Coefficient for first delay
    input logic signed [15:0] coeff2, // Coefficient for second delay
    input logic signed [15:0] coeff3  // Coefficient for third delay
);

    // Declare internal storage for delay elements and accumulation
    logic signed [15:0] sample_delay1, sample_delay2, sample_delay3;
    logic signed [31:0] accumulator;

    // Sequential block to handle operations on clock or reset
    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset state: Clear all registers and output
            sample_delay1 = 0;
            sample_delay2 = 0;
            sample_delay3 = 0;
            accumulator = 0;
        else begin
            // Regular operation: Shift samples, compute filtered output
            sample_delay1 = input_sample;
            sample_delay2 = sample_delay1;
            sample_delay3 = sample_delay2;

            // Compute the accumulator with signed multiplication
            accumulator = accumulator + (coeff0 * sample_delay1) + (coeff1 * sample_delay2) + (coeff2 * sample_delay3);

            // After 4 clock cycles, assign the accumulator to output_sample
            #4 output_sample = accumulator;
        end
    end
endmodule

module fir_filter (
    input wire clk,                  // Clock signal
    input wire reset,                // Asynchronous reset
    input wire [15:0] data_in,       // Input data
    output reg [15:0] data_out,      // Filtered output data
    input wire [1:0] window_type     // Window type selector: 0-Rectangular, 1-Hanning, 2-Hamming, 3-Blackman
);

    reg [15:0] coeff0, coeff1, coeff2, coeff3, coeff4, coeff5, coeff6, coeff7;
    reg [15:0] shift_reg0, shift_reg1, shift_reg2, shift_reg3, shift_reg4, shift_reg5, shift_reg6, shift_reg7;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out = 0;
            shift_reg0 = 0;
            shift_reg1 = 0;
            shift_reg2 = 0;
            shift_reg3 = 0;
            shift_reg4 = 0;
            shift_reg5 = 0;
            shift_reg6 = 0;
            shift_reg7 = 0;
        else begin
            shift_reg0 = data_in;
            shift_reg1 = shift_reg0;
            shift_reg2 = shift_reg1;
            shift_reg3 = shift_reg2;
            shift_reg4 = shift_reg3;
            shift_reg5 = shift_reg4;
            shift_reg6 = shift_reg5;
            shift_reg7 = shift_reg6;

            case (window_type)
                2'b00: coeff0 = 10; coeff1 = 11; coeff2 = 12; coeff3 = 13; coeff4 = 14; coeff5 = 15; coeff6 = 16; coeff7 = 17;
                2'b01: coeff0 = 2; coeff1 = 4; coeff2 = 8; coeff3 = 12; coeff4 = 12; coeff5 = 8; coeff6 = 4; coeff7 = 2;
                2'b10: coeff0 = 3; coeff1 = 6; coeff2 = 9; coeff3 = 11; coeff4 = 11; coeff5 = 9; coeff6 = 6; coeff7 = 3;
                2'b11: coeff0 = 1; coeff1 = 2; coeff2 = 5; coeff3 = 9; coeff4 = 9; coeff5 = 5; coeff6 = 2; coeff7 = 1;
                default: coeff0 = 0; coeff1 = 0; coeff2 = 0; coeff3 = 0; coeff4 = 0; coeff5 = 0; coeff6 = 0; coeff7 = 0;
            endcase

            data_out = (shift_reg0 * coeff0) + (shift_reg1 * coeff1) + (shift_reg2 * coeff2) + (shift_reg3 * coeff3) + (shift_reg4 * coeff4) + (shift_reg5 * coeff5) + (shift_reg6 * coeff6) + (shift_reg7 * coeff7);
            data_out = data_out >>> 4;
        end
    end
endmodule

