output.rtl/serial_line_code_converter.sv:
module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse <= 0;
        end else begin
            clk_counter <= clk_counter + 1;
            if (clk_counter == CLK_DIV - 1) begin
                clk_pulse <= 1;
                clk_counter <= 0;
            end
            else begin
                clk_pulse <= 0;
            end
        end
    end

    // Return-to-Zero Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else begin
            if (clk_pulse) begin
                rz_out <= serial_in & ~prev_serial_in;
            else begin
                rz_out <= 0;
            end
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else begin
            diff_out <= serial_in ^ prev_serial_in;
        end
    end

    // Inverted NRZ Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else begin
            inv_nrz_out <= ~serial_in;
        end
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_out <= 0;
            alt_invert_state <= 0;
        end else begin
            alt_invert_out <= serial_in ^ alt_invert_state;
            alt_invert_state <= ~alt_invert_state;
        end
    end

    // Parity Bit Output
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else begin
            parity_out <= parity_out ^ serial_in;
        end
    end

    // Scrambled NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else begin
            scrambled_out <= serial_in ^ (clk_counter & 1);
        end
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else begin
            edge_triggered_out <= serial_in ^ prev_serial_in;
        end
    end

    // Output Multiplexer
    integer mode_val = (mode [2:0]);
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            nrz_out <= 0;
            rz_out <= 0;
            diff_out <= 0;
            inv_nrz_out <= 0;
            alt_invert_out <= 0;
            parity_out <= 0;
            scrambled_out <= 0;
            edge_triggered_out <= 0;
        end else if (mode_val < 8) begin
            case (mode_val)
                0: serial_out <= nrz_out;
                1: serial_out <= rz_out;
                2: serial_out <= diff_out;
                3: serial_out <= inv_nrz_out;
                4: serial_out <= alt_invert_out;
                5: serial_out <= parity_out;
                6: serial_out <= scrambled_out;
                7: serial_out <= edge_triggered_out;
                default: serial_out <= 0;
            endcase
        else begin
            serial_out <= 0;
        end
    end
endmodule

module serial_line_code_converter #(parameter CLK_DIV = 16),
    (parameter [4:0] mode)  // 5-bit mode selector including error detection
    (input  logic clk,             // System clock
     input  logic reset_n,         // Active-low reset
     input  logic enable,          // Enable signal
     input  logic serial_in,       // Serial input signal
     input  logic [2:0] mode)      // Mode selector
    (output logic serial_out       // Serial output signal
     , output [15:0] diagnostic_bus)  // Diagnostic output bus
     , output logic error_flag      // Error flag output
     , output logic error_counter); // Error counter output

    // Internal signals
    logic [3:0]clk_counter;      // Clock divider counter
    logicclk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output
    logic [4:0] error_code;       // Error code output
    logic [15:0] diagnostic_bus;  //Diagnostic output bus

    // Internal registers
    reg [7:0] error_counter;     // 8-bit error counter
    reg error_flag;              // Error flag

    // Internal signals for diagnostic bus
    logic [3:0] clock_pulse_state; // Clock pulse status
    logic encoded_output;         // Encoded output
    logic alt_invert_state;       // Alternating inversion state
    logic parity_bit;             // Parity bit

    // Internal signals for error detection
    logic invalid_serial_in;     // Flag for invalid serial_in
    logic [15:0] diagnostic_bits; // Diagnostic output bus

    // Internal signals for error detection
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse <= 0;
            prev_value <= 0;
            prev_serial_in <= 0;
            invalid_serial_in <= 0;
            error_flag <= 0;
            error_counter <= 0;
        end else begin
            prev_value <= serial_in;
            prev_serial_in <= prev_value;
            invalid_serial_in <= 0;
            error_flag <= 0;
            error_counter <= 0;
        end
    end

    // Always blocks
    always_comb begin
        case (mode)
            5'b00000: serial_out = nrz_out;
                        error_code = 5'b00000;
                        clock_pulse_state = 0;
                        encoded_output = nrz_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00001: serial_out = rz_out;
                        error_code = 5'b00001;
                        clock_pulse_state = 0;
                        encoded_output = rz_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00010: serial_out = diff_out;
                        error_code = 5'b00010;
                        clock_pulse_state = 0;
                        encoded_output = diff_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00011: serial_out = inv_nrz_out;
                        error_code = 5'b00011;
                        clock_pulse_state = 0;
                        encoded_output = inv_nrz_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00100: serial_out = alt_invert_out;
                        error_code = 5'b00100;
                        clock_pulse_state = 0;
                        encoded_output = alt_invert_out;
                        alt_invert_state = 1;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00101: serial_out = parity_out;
                        error_code = 5'b00101;
                        clock_pulse_state = 0;
                        encoded_output = parity_out;
                        alt_invert_state = 0;
                        parity_bit = 1;
                        invalid_serial_in = 0;
            5'b00110: serial_out = scrambled_out;
                        error_code = 5'b00110;
                        clock_pulse_state = 0;
                        encoded_output = scrambled_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            5'b00111: serial_out = edge_triggered_out;
                        error_code = 5'b00111;
                        clock_pulse_state = 0;
                        encoded_output = edge_triggered_out;
                        alt_invert_state = 0;
                        parity_bit = 0;
                        invalid_serial_in = 0;
            default: serial_out = 0;
                        error_flag = 0;
                        error_counter = 0;
                        invalid_serial_in = 0;
        endcase
    end

    // Error detection logic
    always_comb begin
        if (invalid_serial_in) begin
            error_flag <= 1;
            error_counter <= error_counter + 1;
        end
    end

    // Diagnostic bus assignment
    always_comb begin
        diagnostic_bus[15:13] = mode;
        diagnostic_bus[12] = error_flag;
        diagnostic_bus[11:4] = error_counter;
        diagnostic_bus[3] = clock_pulse_state;
        diagnostic_bus[2] = encoded_output;
        diagnostic_bus[1] = alt_invert_state;
        diagnostic_bus[0] = parity_bit;
    end

    // Enable control
    always_comb begin
        if (enable) begin
            // All logic remains the same when enable is high
        end else begin
            // Reset all outputs to 0 when enable is low
            serial_out <= 0;
            error_flag <= 0;
            error_counter <= 0;
            invalid_serial_in <= 0;
        end
    end

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

