// APB DSP Operation Module
module apb_dsp_op #(
    parameter ADDR_WIDTH = 'd8,
    parameter DATA_WIDTH = 'd32
) (
    input  logic                  clk_dsp,    // Faster clock to DSP operation
    input  logic                  en_clk_dsp, // Enable DSP operation with faster clock
    input  logic                  PCLK,       // APB clock
    input  logic                  PRESETn,    // Active low asynchronous APB Reset
    input  logic [ADDR_WIDTH-1:0] PADDR,      // APB address
    input  logic [DATA_WIDTH-1:0] PWDATA,     // Write data
    input  logic [32:0] PSEL,       // DSP selector
    input  logic [1:0] PENABLE,     // APB enable
    output logic [DATA_WIDTH-1:0] PRDATA,     // Read data
    output logic                  PREADY      // Ready signal
);

    // APB interface logic
    logic [DATA_WIDTH-1:0] sram_data_in;
    logic                         sram_we;
    logic [ADDR_WIDTH-1:0] sram_addr;
    logic [DATA_WIDTH-1:0] sram_data_out;

    // APB clock synchronizer
    logic clock_synchronizer = (
        (posedge PCLK or posedge en_clk_dsp) && 
        (negedge PCLK or negedge en_clk_dsp)
    );

    // Clock sel logic
    assign dsp_clk_sel = (en_clk_dsp) ? clk_dsp : PCLK;

    // Internal registers address map
    localparam ADDRESS_A         = 32'h0;  // 0x00
    localparam ADDRESS_B         = 32'h4;  // 0x04
    localparam ADDRESS_C         = 32'h8;  // 0x08
    localparam ADDRESS_O         = 32'hC;  // 0x0C
    localparam ADDRESS_CONTROL   = 32'h10; // 0x10
    localparam ADDRESS_WDATA     = 32'h14; // 0x14
    localparam ADDRESS_SRAM_ADDR = 32'h18; // 0x18

    // Control modes
    localparam SRAM_WRITE     = 32'd1;
    localparam SRAM_READ      = 32'd2;
    localparam DSP_READ_OP_A  = 32'd3;
    localparam DSP_READ_OP_B  = 32'd4;
    localparam DSP_READ_OP_C  = 32'd5;
    localparam DSP_WRITE_OP_O = 32'd6;

    // Internal signals
    logic [DATA_WIDTH-1:0] reg_operand_a;
    logic [DATA_WIDTH-1:0] reg_operand_b;
    logic [DATA_WIDTH-1:0] reg_operand_c;
    logic [DATA_WIDTH-1:0] reg_operand_o;
    logic [DATA_WIDTH-1:0] reg_control;
    logic [DATA_WIDTH-1:0] reg_wdata_sram;
    logic [DATA_WIDTH-1:0] reg_addr_sram;

    // APB interface logic
    always_ff @(posedge PCLK or negedge PRESETn) begin
        if (!PRESETn) begin
            reg_operand_a  <= 'd0;
            reg_operand_b  <= 'd0;
            reg_operand_c  <= 'd0;
            reg_operand_o  <= 'd0;
            reg_control    <= 'd0;
            reg_wdata_sram <= 'd0;
            reg_addr_sram  <= 'd0;
            PREADY <= 1'b0;
        end else if (PENABLE & PSEL) begin
            PREADY <= 1'b1;
            if (PWRITE) begin
                case (PADDR)
                    ADDRESS_A         : reg_operand_a  <= PWDATA;
                    ADDRESS_B         : reg_operand_b  <= PWDATA;
                    ADDRESS_C         : reg_operand_c  <= PWDATA;
                    ADDRESS_O         : reg_operand_o  <= PWDATA;
                    ADDRESS_CONTROL   : reg_control    <= PWDATA;
                    ADDRESS_WDATA     : reg_wdata_sram <= PWDATA;
                    ADDRESS_SRAM_ADDR : reg_addr_sram  <= PWDATA;
                endcase
            end else begin
                if (reg_control == SRAM_READ) begin
                    PRDATA <= sram_data_out;
                end else begin
                    case (PADDR)
                        ADDRESS_A         : PRDATA <= reg_operand_a;
                        ADDRESS_B         : PRDATA <= reg_operand_b;
                        ADDRESS_C         : PRDATA <= reg_operand_c;
                        ADDRESS_O         : PRDATA <= reg_operand_o;
                        ADDRESS_CONTROL   : PRDATA <= reg_control;
                        ADDRESS_WDATA     : PRDATA <= reg_wdata_sram;
                        ADDRESS_SRAM_ADDR : PRDATA <= reg_addr_sram;
                    endcase
                end               
            end
        end
    end

    // SRAM logic
    logic [DATA_WIDTH-1:0] mem [63:0];

    always_comb begin
        sram_data_in = (reg_control == SRAM_WRITE) ? reg_wdata_sram : wire_op_o;

        if ((reg_control == SRAM_WRITE) || (reg_control == DSP_WRITE_OP_O)) begin
            sram_we = 1'b1;
        end else begin
            sram_we = 1'b0;
        end

        case (reg_control)
            DSP_READ_OP_A  : sram_addr = reg_operand_a;
            DSP_READ_OP_B  : sram_addr = reg_operand_b;
            DSP_READ_OP_C  : sram_addr = reg_operand_c;
            DSP_WRITE_OP_O : sram_addr = reg_operand_o;
            default        : sram_addr = reg_addr_sram;
        endcase
    end

    always_ff @(posedge PCLK) begin
        if (sram_we) begin
            mem[sram_addr] <= sram_data_in;
        end else begin
            sram_data_out <= mem[sram_addr];
        end
    end

    // DSP operation
    always_ff @(posedge dsp_clk_sel) begin
        case (reg_control)
            DSP_READ_OP_A  : wire_op_a <= sram_data_out;
            DSP_READ_OP_B  : wire_op_b <= sram_data_out;
            DSP_READ_OP_C  : wire_op_c <= sram_data_out;
        endcase
    end

    // SRAM address validation
    always_ff @(posedge PCLK) begin
        if (sram_we) begin
            if (reg_addr_sram & 0x0F) != 0x00 begin
                PSLVERR = 1'b1;
            end
        end
    end

    // Synchronizer
    logic clock_synchronizer = (
        (posedge PCLK && posedge en_clk_dsp) || 
        (negedge PCLK && negedge en_clk_dsp)
    );

    // Final PREADY assertion
    always_ff @(posedge PCLK) begin
        if (sram_we) begin
            if (reg_addr_sram & 0x0F) == 0x00 begin
                PREADY = 1'b1;
            end else begin
                PREADY = 1'b0;
            end
        else begin
            PREADY = 1'b1;
        end
    end

output.rtl/apb_dsp_unit.v:
module apb_dsp_unit (
    input wire pclk,
    input wire presetn,
    input wire paddr,
    input wire pselx,
    input wire penable,
    input wire pwrite,
    input wire pwdata,
    output reg prdata,
    output reg pready,
    output reg pslverr,
    input wire sram_valid
) {

    // State machine
    reg state = IDLE;
    reg [7:0] result;

    // Register definitions
    reg [7:0] r_operand_1, r_operand_2, r_Enable, r_write_address, r_write_data;

    // Initialize registers
    initial begin
        r_operand_1 = 0;
        r_operand_2 = 0;
        r_Enable = 0;
        r_write_address = 0;
        r_write_data = 0;
        prdata = 0;
        pready = 0;
        pslverr = 0;
    end

    // State transitions
    always @* begin
        case (state)
            IDLE:
                if (presetn) begin
                    // Reset all registers and outputs
                    prdata = 0;
                    pready = 0;
                    pslverr = 0;
                    r_operand_1 = 0;
                    r_operand_2 = 0;
                    r_Enable = 0;
                    r_write_address = 0;
                    r_write_data = 0;
                    state = IDLE;
                end
                else begin
                    // Transition to READ or WRITE state based on r_Enable
                    if (r_Enable == 0) state = IDLE;
                    else if (r_Enable == 1 || r_Enable == 2) state = READ;
                    else if (r_Enable == 3) state = WRITE;
                end
            READ:
                // Read operands and compute result
                result = r_operand_1 + r_operand_2;
                prdata = result;
                pready = 1;
                state = IDLE;
            WRITE:
                if (sram_valid) begin
                    r_write_data = pwdata;
                    prdata = 0;
                    pready = 1;
                    state = IDLE;
                else begin
                    // Error condition
                    pslverr = 1;
                    state = IDLE;
                end
            END
        endcase
    end

    // APB Interface
    wire [7:0] apb_data;
    wire [9:0] apb_addr;

    // APB to Module Interface
    apb_addr = paddr;
    apb_data = pwdata;

    // Module to APB Interface
    if (state == IDLE) begin
        prdata = 0;
        pready = 0;
        pslverr = 0;
    end
    else if (state == READ) begin
        prdata = prdata;
        pready = 1;
        pslverr = 0;
    end
    else if (state == WRITE) begin
        prdata = 0;
        pready = 1;
        pslverr = 0;
    end

    // SRAM Interface
    always @* begin
        if (sram_valid) begin
            if (pready) begin
                r_write_data = prdata;
                r_write_address = apb_addr;
                pready = 0;
            end
        end
    end
}

