                csr_reg[axi_awaddr_i[4:2]] <= axi_wdata_i;
                axi_awready_o <= 1;
                axi_wready_o  <= 1;
                axi_bvalid_o  <= 1; // Set response valid
            end else begin
                axi_awready_o <= 0;
                axi_wready_o  <= 0;
                axi_bvalid_o  <= 0; // Set response valid
            end

            // Handle Write Response
            if (axi_bvalid_o && axi_bready_i) begin
                axi_bvalid_o <= 0; // Clear response once acknowledged
            end

            // Handle AXI Read
            if (axi_arvalid_i) begin
                axi_arready_o <= 1;
                axi_rvalid_o  <= 1;
                axi_rdata_o    <= csr_reg[axi_araddr_i[4:2]];
            end else begin
                axi_arready_o <= 0;
                axi_rvalid_o  <= 0;
            end

            // Update CSR Registers
            operand_a     <= csr_reg[0];
            operand_b     <= csr_reg[1];
            operand_c     <= csr_reg[2];
            op_select     <= csr_reg[3][1:0];
            start         <= csr_reg[3][2];
            clock_control <= csr_reg[4][0];
        end
    end
endmodule

// ------------------------------------------------------------------
// Memory Block (ROM)
// ------------------------------------------------------------------
module memory_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [5:0]  address_a,
    input  wire [5:0]  address_b,
    input  wire [5:0]  address_c,
    output wire [31:0] data_a,
    output wire [31:0] data_b,
    output wire [31:0] data_c
);
    reg [31:0] rom [0:63];

    initial begin
        $readmemh("../rom_data.mem", rom);
    end

    assign data_a = (reset_in) ? 32'd0 : rom[address_a];
    assign data_b = (reset_in) ? 32'd0 : rom[address_b];
    assign data_c = (reset_in) ? 32'd0 : rom[address_c];
endmodule

// ------------------------------------------------------------------
// DSP Processing Block
// ------------------------------------------------------------------
module dsp_block (
    input  wire        clk,
    input  wire        reset_in,
    input  wire [31:0] operand_a,
    input  wire [31:0] operand_b,
    input  wire [31:0] operand_c,
    input  wire [1:0]  op_select,
    input  wire        start,
    output reg  [63:0] result
);
    always @(posedge clk or posedge reset_in) begin
        if (reset_in)
            result <= 64'd0;
        else begin
            if (start) begin
                case (op_select)
                    2'b00: result <= (operand_a + operand_b) * operand_c;    // MAC
                    2'b01: result <= operand_a * operand_b;    // Multiplication
                    2'b10: result <= operand_a >> operand_b[4:0]; // Shift Right
                    2'b11: result <= operand_b ? operand_a / operand_b : 64'hDEADDEAD; // Division (handle divide by zero)
                endcase
            end
        end
    end
endmodule

output.rtl/axi_register.sv:
module axi_register(
    input clock,
    input rst,
    input [ADDR_WIDTH-1:0] awaddr,
    input [DATA_WIDTH-1:0] wdata,
    input [DATA_WIDTH/8-1:0] wstrb,
    input wvalid,
    input bready,
    input [ADDR_WIDTH-1:0] araddr,
    input arvalid,
    input rready,
    input done
);

    // Configuration parameters
    parameter DATA_WIDTH = 32;
    parameter ADDR_WIDTH = 32;

    // Register map
    reg [19:0] beat = 0x00000000;
    reg start = 0;
    reg [1:0] done_reg = {0, 0};
    reg writeback = 0;
    reg [32-1:0] id = 0x00010000;

    // AXI4-Lite initialization
    always_comb begin
        if (rst) begin
            beat = 0;
            start = 0;
            done_reg = {0, 0};
            writeback = 0;
            id = 0x00010000;
            $valid_out(0);
            $ready_out(1);
        end

        // Write operation
        if (arvalid && wvalid) begin
            $valid_out(wvalid);
            if (wstrb[0]) begin
                if (wvalid) begin
                    beat = (beat + wdata) & ((1 << DATA_WIDTH) - 1);
                    start = (wdata & 1) ? 1 : 0;
                    done_reg[0] = ~done_reg[0];
                    writeback = (wdata & 1) ? 1 : 0;
                end
            end
            $ready_out(0);
        end

        // Read operation
        if (arvalid && arvalid) begin
            $valid_out(arvalid);
            rdata = beat;
            done_reg[1] = ~done_reg[1];
            $ready_out(0);
        end
    end

    // Error handling
    wire [2:0] bresp = {0, 0};
    wire [1:0] rresp = {0, 0};

    // Outputs
    output awready, wready, bresp, bvalid, arready, wvalid, rvalid, rdata, rresp, start, done, writeback;
endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  inputclk,          //Global clock signal: Signals are sampled on the rising edge of clk
  inputresetn,       //The global reset signal: resetn is synchronous active-LOW reset.
  input s_valid,     //The s_axis_valid signal indicates that the slave is driving a valid transfer.
  output reg s_ready, //The s_axis_ready indicates that the slave can accept a transfer in the current cycle.
  input [15:0] s_data, //The s_axis_data is the primary payload data from slave.
  output reg m_valid, //The m_axis_valid indicates that the master is driving a valid transfer.
  input m_ready,      //The m_axis_ready indicates that the slave can accept a transfer in the current cycle.
  output reg [7:0] m_data //The m_axis_data is the primary payload data to master.
);

  // FIFO buffer for 16-bit data
  reg [15:0] data_FIFO;

  // State machine control
  always @(posedge clk or posedge resetn) begin
    if (resetn) begin
      data_FIFO = 0;
      m_data = 0;
      s_ready = 1;
    elsif s_valid begin
      data_FIFO = s_data;
      s_ready = 1;
    elsif m_ready begin
      if (data_FIFO[7:0]) begin
        m_data = data_FIFO[7:0];
        m_valid = 1;
        data_FIFO = data_FIFO[15:8];
      end else if (data_FIFO[15:8]) begin
        m_data = data_FIFO[15:8];
        m_valid = 1;
        data_FIFO = 0;
      end
    end
  end
endmodule

output.rtl/axis_upscale.sv:
module axis_upscale(
    input clock,
    input resetn,
    input dfmt_enable,
    input dfmt_type,
    input dfmt_se,
    input s_axis_valid,
    input s_axis_data,
    output m_axis_valid,
    output m_axis_data,
    output s_axis_ready
);

    // Reset handling
    reg [31:0] m_axis_data = 0;
    reg s_axis_ready = 0;

    always_comb begin
        if (resetn) begin
            m_axis_valid = 0;
            s_axis_ready = 0;
        else begin
            case (dfmt_enable)
                0: begin
                    m_axis_valid = 1;
                    if (s_axis_valid) begin
                        m_axis_data = s_axis_data;
                        m_axis_data = (m_axis_data << 8) | (4'b0000);
                    end
                end
                1: begin
                    m_axis_valid = 1;
                    if (s_axis_valid) begin
                        // Sign extension
                        bit sign_bit = (s_axis_data & 8'h10000000) >> 23;
                        sign_bit = (dfmt_se) ? sign_bit : 0;
                        sign_bit = (dfmt_type) ? (~sign_bit) : sign_bit;
                        m_axis_data = (s_axis_data << 8) | (4#(sign_bit));
                    end
                end
            endcase
        end
    end

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32
)(
    input           clk_i,
    input           rst_i,
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    input           inport_awready_o,
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,
    output          outport_awready_i,
    output          outport_awvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_awaddr_o,
    output          outport_wready_i,
    output          outport_wvalid_o,
    output  [DATA_WIDTH-1:0]   outport_wdata_o,
    output  [3:0]    outport_wstrb_o,
    output          outport_bvalid_i,
    input           outport_bready_o,
    output          outport_bresp_i,
    output [1:0]    outport_bresp_o,
    input           outport_arready_i,
    output          outport_arvalid_o,
    output  [ADDR_WIDTH-1:0]   outport_araddr_o,
    output          outport_rready_i,
    output          outport_rvalid_o,
    output  [DATA_WIDTH-1:0]   outport_rdata_i,
    output [1:0]    outport_rresp_i
);

// Address decoding logic
reg [3:0]    address_mask = 0x80000000;
reg [3:0]    peripheral_address = inport_awaddr_i & address_mask;

// Read FIFO
reg [ADDR_WIDTH-1:0]    read_pending_q;
reg [3:0]    read_port_q;

always @ (posedge clk_i) begin
    if (rst_i) begin
        read_pending_q = 0;
        read_port_q = 0;
    else
        read_port_q = read_pending_q;
        read_pending_q = inport_araddr_i & address_mask;
    end
end

// Read logic
reg [3:0]    read_accept_w;
wire read_port_r = inport_araddr_i & address_mask;

always @ (posedge clk_i) begin
    if (rst_i) begin
        read_port_r = 0;
    end else if (inport_arvalid_i & inport_arready_o) begin
        read_port_r = read_port_q;
    end else if (read_port_q == 0) begin
        read_port_r = 0;
    end
end

always @ (posedge clk_i) begin
    if (rst_i) begin
        read_accept_w = 0;
    else if (inport_arvalid_i & inport_arready_o) begin
        read_accept_w = 1;
    else if (read_port_q == 0) begin
        read_accept_w = 0;
    end
end

// Write FIFO
reg [3:0]    write_port_q;
reg [ADDR_WIDTH-1:0]    write_port_r;

always @ (posedge clk_i) begin
    if (rst_i) begin
        write_port_q = 0;
        write_port_r = 0;
    else
        write_port_q = write_port_r;
        write_port_r = inport_awaddr_i & address_mask;
    end
end

// Write logic
wire write_accept_w = (write_port_q == write_port_r) | (write_port_r == 0);

always @ (posedge clk_i) begin
    if (rst_i) begin
        write_accept_w = 0;
    end else if (inport_awvalid_i & inport_awready_o) begin
        write_accept_w = 1;
    end else if (write_port_q == 0) begin
        write_accept_w = 0;
    end
end

//Peripheral 0 interface
wire outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == 0);
wire outport_peripheral0_awaddr_o = inport_awaddr_i;
wire outport_peripheral0_wvalid_o = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i | awvalid_q) & (write_port_r == 0);
wire outport_peripheral0_wdata_o = inport_wdata_i;
wire outport_peripheral0_wstrb_o = inport_wstrb_i;
wire outport_peripheral0_bvalid_o = inport_bvalid_i;
wire outport_peripheral0_bresp_o = inport_bresp_i;

// Default interface
wire outport_default_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == 1);
wire outport_default_awaddr_o = inport_awaddr_i;
wire outport_default_wvalid_o = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i | awvalid_q) & (write_port_r == 1);
wire outport_default_wdata_o = inport_wdata_i;
wire outport_default_wstrb_o = inport_wstrb_i;
wire outport_default_bvalid_o = inport_bvalid_i;
wire outport_default_bresp_o = inport_bresp_i;

// peripheral0 response
wire outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == 0);
wire outport_peripheral0_araddr_o = inport_araddr_i;
wire outport_peripheral0_rvalid_o = inport_rvalid_i;
wire outport_peripheral0_rdata_o = inport_rdata_i;
wire outport_peripheral0_rresp_o = inport_rresp_i;

// default response
wire outport_default_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == 1);
wire outport_default_araddr_o = inport_araddr_i;
wire outport_default_rvalid_o = inport_rvalid_i;
wire outport_default_rdata_o = inport_rdata_i;
wire outport_default_rresp_o = inport_rresp_i;

// peripheral0 write
wire outport_peripheral0_wvalid_o = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i | awvalid_q) & (write_port_r == 0);
wire outport_peripheral0_wdata_o = inport_wdata_i;
wire outport_peripheral0_wstrb_o = inport_wstrb_i;

// default write
wire outport_default_wvalid_o = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i | awvalid_q) & (write_port_r == 1);
wire outport_default_wdata_o = inport_wdata_i;
wire outport_default_wstrb_o = inport_wstrb_i;

// peripheral0 response
wire outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == 0);
wire outport_peripheral0_araddr_o = inport_araddr_i;
wire outport_peripheral0_rvalid_o = inport_rvalid_i;
wire outport_peripheral0_rdata_o = inport_rdata_i;
wire outport_peripheral0_rresp_o = inport_rresp_i;

// default response
wire outport_default_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == 1);
wire outport_default_araddr_o = inport_araddr_i;
wire outport_default_rvalid_o = inport_rvalid_i;
wire outport_default_rdata_o = inport_rdata_i;
wire outport_default_rresp_o = inport_rresp_i;

// peripheral0 response
wire outport_peripheral0_bvalid_o = inport_bvalid_i;
wire outport_peripheral0_bresp_o = inport_bresp_i;

// default response
wire outport_default_bvalid_o = inport_bvalid_i;
wire outport_default_bresp_o = inport_bresp_i;

endmodule

input.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

always @ *
begin
    read_port_r = `ADDR_SEL_W'b0;
    if ((inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) read_port_r = `ADDR_SEL_W'd1;
end

wire read_incr_w = (inport_arvalid_i && inport_arready_o);
wire read_decr_w = (inport_rvalid_o && inport_rready_i);

always @ *
begin
    read_pending_r = read_pending_q;

    if (read_incr_w && !read_decr_w)
        read_pending_r = read_pending_r + 4'd1;
    else if (!read_incr_w && read_decr_w)
        read_pending_r = read_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;

    // Read command accepted
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

reg        outport_rvalid_r;
reg [DATA_WIDTH-1:0] outport_rdata_r;
reg [1:0]  outport_rresp_r;

always @ *
begin
    case (read_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_rvalid_r = outport_peripheral0_rvalid_i;
        outport_rdata_r  = outport_peripheral0_rdata_i;
        outport_rresp_r  = outport_peripheral0_rresp_i;
    end
    default:
    begin
        outport_rvalid_r = outport_rvalid_i;
        outport_rdata_r  = outport_rdata_i;
        outport_rresp_r  = outport_rresp_i;
    end
    endcase
end

assign inport_rvalid_o  = outport_rvalid_r;
assign inport_rdata_o   = outport_rdata_r;
assign inport_rresp_o   = outport_rresp_r;

reg inport_arready_r;
always @ *
begin
    case (read_port_r)
    `ADDR_SEL_W'd1:
        inport_arready_r = outport_peripheral0_arready_i;
    default:
        inport_arready_r = outport_arready_i;
    endcase
end

assign inport_arready_o = read_accept_w & inport_arready_r;

//-------------------------------------------------------------
// Write Request
//-------------------------------------------------------------
reg awvalid_q;
reg wvalid_q;

wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

always @ (posedge clk_i )
if (rst_i)
    awvalid_q <= 1'b0;
else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
    awvalid_q <= 1'b1;
else if (wr_data_accepted_w)
    awvalid_q <= 1'b0;

always @ (posedge clk_i )
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_o && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 1'b0;

//-----------------------------------------------------------------
// AXI: Write
//-----------------------------------------------------------------
reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_SEL_W-1:0]  write_port_q;
reg [`ADDR_SEL_W-1:0]  write_port_r;

always @ *
begin    
    if (inport_awvalid_i & ~awvalid_q)
    begin
        write_port_r = `ADDR_SEL_W'b0;
        if ((inport_awaddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) write_port_r = `ADDR_SEL_W'd1;
    end
    else
        write_port_r = write_port_q;
end

wire write_incr_w = (inport_awvalid_i && inport_awready_o);
wire write_decr_w = (inport_bvalid_o  && inport_bready_i);

always @ *
begin
    write_pending_r = write_pending_q;

    if (write_incr_w && !write_decr_w)
        write_pending_r = write_pending_r + 4'd1;
    else if (!write_incr_w && write_decr_w)
        write_pending_r = write_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    write_pending_q <= write_pending_r;

    // Write command accepted
    if (inport_awvalid_i && inport_awready_o)
    begin
        write_port_q <= write_port_r;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o   = inport_wdata_i;
