module bus_arbiter (
    input wire reset,
    input wire clk,
    input wire req1,
    input wire req2,
    output reg grant1,
    output reg grant2
);
    // State encoding using localparam
    localparam IDLE    = 3'b000,
               GRANT_1 = 3'b001,
               GRANT_2 = 3'b010,
               CLEAR   = 3'b011;

    // State registers
    reg [2:0] state;
    reg [2:0] next_state;

    // Sequential logic for state transition
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // Combinational logic for next state
    always @(*) begin
        // Default assignments
        next_state = state;

        case (state)
            IDLE: 
                next_state = IDLE;
                if (req1) next_state = GRANT_1;
                else if (req2) next_state = GRANT_2;
                else next_state = IDLE;
            GRANT_1:
                next_state = CLEAR if req2 else IDLE;
            GRANT_2:
                next_state = IDLE;
            CLEAR:
                next_state = IDLE;
        endcase
    end

    // Output logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end else begin
            grant1 <= (next_state == GRANT_1);
            grant2 <= (next_state == GRANT_2);
        end
    end

endmodule

