output.rtl/signed_comparator.sv:
module signed_unsigned_comparator(
    parameter WIDTH = 5,
    input WIDTH i_A,
    input WIDTH i_B,
    input 1 bit i_enable,
    input 1 bit i_mode,
    output 1 bit o_greater,
    output 1 bit o_less,
    output 1 bit o_equal
);

    if (i_enable == 0)
        o_greater = 0;
        o_less = 0;
        o_equal = 0;
    else
        local bit a_sign, b_sign, a_value, b_value;
        a_sign = (i_A >> (WIDTH - 1)) & 1;
        b_sign = (i_B >> (WIDTH - 1)) & 1;
        a_value = i_A & ((1 << WIDTH) - 1);
        b_value = i_B & ((1 << WIDTH) - 1);

        if (a_sign != b_sign)
            if (a_sign == 0)
                o_greater = 1;
            else
                o_less = 1;
        else
            if (a_value > b_value)
                o_greater = 1;
            else if (a_value < b_value)
                o_less = 1;
            else
                o_equal = 1;
    end

endmodule

output.rtl/compression_engine.sv:
module compression_engine (
  input   logic        clk,
  input   logic        reset,
  input   logic [23:0] num_i,
  output  logic [11:0] mantissa_o,
  output  logic [3:0]  exponent_o
);

  // --------------------------------------------------------
  // One-Hot Encoding of the Exponent
  // --------------------------------------------------------
  logic [23:0] exp_oh;
  assign exp_oh[23] = num_i[23];
  generate
    for (integer i = 22; i >= 0; i = i - 1)
      exp_oh[i] = num_i[i] & ~num_i[i+1:23];
  endgenerate

  // Use the `onehot_to_bin` module to convert one-hot to binary exponent
  onehot_to_bin #(
    .ONE_HOT_W(24),
    .BIN_W(4)
  ) exp_oh_bin (
    .oh_vec_i(exp_oh),
    .bin_vec_o(exp_bin)
  );

  assign exponent = (|exp_oh) ? exp_bin : 0;

  // --------------------------------------------------------
  // Mantissa Extraction Logic
  // --------------------------------------------------------
  logic [11:0] mantissa;

  if (num_i == 0)
    mantissa = 0;
  else
    mantissa = num_i[exponent + 11 : exponent];

  // --------------------------------------------------------
  // Output assignments
  // --------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      exponent_o <= 4'd0;
      mantissa_o <= 12'd0;
    end else begin
      exponent_o <= exponent;
      mantissa_o <= mantissa;
    end
  end

endmodule

output.rtl/enhanced_fsm_signal_processor.v:
module enhanced_fsm_signal_processor (
    input clock,
    input rst_n,
    input enable,
    input clear,
    input acknowledge,
    input vector_1,
    input vector_2,
    input vector_3,
    input vector_4,
    input vector_5,
    input vector_6,
    output reg fsm_state,
    output reg o_ready,
    output reg o_error,
    output reg [1:0] o_fsm_status,
    output reg vector_1,
    output reg vector_2,
    output reg vector_3,
    output reg vector_4
);

    reg fsm_state = 00;
    reg [30:0] process_bus = 0;
    reg [7:0] state_reg;

    always @posedge clock begin
        if (rst_n) begin
            fsm_state = 00;
            state_reg = 0;
            o_ready = 0;
            o_error = 0;
            o_fsm_status = 00;
            vector_1 = 0;
            vector_2 = 0;
            vector_3 = 0;
            vector_4 = 0;
            return;
        end

        case (fsm_state)
        00: begin
            if (enable) begin
                fsm_state = 01;
                state_reg = 0;
            end
        end

        01: begin
            process_bus = vector_1 << 25 | vector_2 << 20 | vector_3 << 15 | vector_4 << 10 | (8'h1 << 9) | (8'h1 << 4);
            state_reg = 1;
            fsm_state = 10;
        end

        10: begin
            if (acknowledge) begin
                fsm_state = 00;
                state_reg = 0;
            end
        end

        11: begin
            if (clear) begin
                fsm_state = 00;
                state_reg = 0;
                o_error = 1;
            end
        end
    end

    // State encoding
    fsm_state = {state_reg[1], state_reg[0]};

    // Output vector mapping
    vector_1 = process_bus[30:24];
    vector_2 = process_bus[19:15];
    vector_3 = process_bus[14:10];
    vector_4 = process_bus[9:5];

output.rtl/low_pass_filter.sv:
module low_pass_filter(
    input wire clk,
    input wire reset,
    input wire [DATA_WIDTH * NUM_TAPS - 1:0] data_in,
    input wire valid_in,
    input wire [COEFF_WIDTH * NUM_TAPS - 1:0] coeffs
    ,
    output wire [NBW_MULT + $clog2(NUM_TAPS) - 1:0] data_out,
    output wire valid_out
);

    // Internal signals
    reg [DATA_WIDTH - 1:0] data_reg[NUM_TAPS - 1:0];
    reg [COEFF_WIDTH - 1:0] coeff_reg[NUM_TAPS - 1:0];
    reg [NBW_MULT - 1:0] taps_mult[NUM_TAPS - 1:0];
    reg sum;
    reg [valid_in] valid_reg;

    always @posedge clk begin
        if (reset) begin
            data_reg[:] = 0;
            coeff_reg[:] = 0;
            sum = 0;
            valid_reg = ~valid_in;
        end else begin
            if (valid_in) begin
                data_reg = data_in;
                coeff_reg = coeffs;
                valid_reg = valid_in;
            end
        end

        // Element-wise multiplication and summation
        taps_mult[0] = (data_reg[0] * coeff_reg[0]);
        taps_mult[1] = (data_reg[1] * coeff_reg[1]);
        taps_mult[2] = (data_reg[2] * coeff_reg[2]);
        taps_mult[3] = (data_reg[3] * coeff_reg[3]);
        taps_mult[4] = (data_reg[4] * coeff_reg[4]);
        taps_mult[5] = (data_reg[5] * coeff_reg[5]);
        taps_mult[6] = (data_reg[6] * coeff_reg[6]);
        taps_mult[7] = (data_reg[7] * coeff_reg[7]);

        sum = taps_mult[0] + taps_mult[1] + taps_mult[2] + taps_mult[3] + taps_mult[4] + taps_mult[5] + taps_mult[6] + taps_mult[7];
    end

    // Set valid_out after processing all taps
    valid_out = valid_in & (sum != 0);

endmodule

output.rtl/decimator_and_peak_detector.sv:
module advanced_decimator_with_adaptive_peak_detection(
    input clock,
    input reset,
    input valid_in,
    input [DATA_WIDTH * N] data_in,
    output [DATA_WIDTH * (N / DEC_FACTOR)] data_out,
    output peak_value,
    output valid_out
);

    // unpack input data into individual samples
    reg [DATA_WIDTH] samples[N];
    integer i, j;

    // initialize decimated samples
    reg [DATA_WIDTH] decimated_samples[N / DEC_FACTOR];

    // unpack data_in into samples
    for (i = 0; i < N; i++) begin
        samples[i] = data_in[(DATA_WIDTH * i)];
    end

    // decimate samples
    for (i = 0; i < N / DEC_FACTOR; i++) begin
        decimated_samples[i] = samples[i * DEC_FACTOR];
    end

    // find peak value
    reg [DATA_WIDTH] current_peak;
    current_peak = decimated_samples[0];
    for (i = 1; i < N / DEC_FACTOR; i++) begin
        if (decimated_samples[i] > current_peak) begin
            current_peak = decimated_samples[i];
        end
    end
    peak_value = current_peak;

    // pack decimated samples into data_out
    data_out = (peak_value) |
               (decimated_samples[0] << DATA_WIDTH) |
               (decimated_samples[1] << (2 * DATA_WIDTH)) |
               // ... continue this pattern for all decimated samples
               (decimated_samples[N / DEC_FACTOR - 1] << ((N / DEC_FACTOR - 1) * DATA_WIDTH));

    // set valid_out based on valid_in and number of samples
    valid_out = valid_in & (N > 0);

endmodule

output.rtl/sgd_linear_regression.sv:
module sgd_linear_regression #(
    parameter DATA_WIDTH = 16, 
    parameter LEARNING_RATE = 3'd1
) (
    input  logicclk,                               // Clock
    input  logic reset,                             // Asynchronous reset
    input  logic signed [DATA_WIDTH-1:0] x_in,      // Input data (x)
    input  logic signed [DATA_WIDTH-1:0] y_true,    // True output (target)
    output logic signed [DATA_WIDTH-1:0] w,     // Trained weight
    output logic signed [DATA_WIDTH-1:0] b      // Trained bias
);
    localparam NBW_PRED  = 2*DATA_WIDTH + 1;
    localparam NBW_ERROR = NBW_PRED + 1;
    localparam NBW_DELTA = 3 + NBW_ERROR + DATA_WIDTH;

    // Intermediate values
    logic signed [NBW_PRED-1:0] y_pred;  
    logic signed [NBW_ERROR-1:0] error;  
    logic signed [NBW_DELTA-1:0] delta_w; 
    logic signed [NBW_DELTA-1:0] delta_b;

    // Predicted output calculation
    always_comb begin
        y_pred = (w * x_in) + b;
    end

    // Error calculation
    error = y_true - y_pred;

    // Weight and bias updates
    always_comb begin
        delta_w = LEARNING_RATE * error * x_in;
        delta_b = LEARNING_RATE * error;
    end

    // Weight and bias adjustment
    always clocked begin
        if (!reset) begin
            w = w + delta_w;
            b = b + delta_b;
        end
    end
endmodule

output.rtl/fsm_linear_reg.sv:
module fsm_linear_reg (
    input clk,
    input reset,
    input start,
    input x_in,
    input w_in,
    input b_in,
    output result1,
    output result2,
    output done
);

    reg state = IDLE;
    reg [DATA_WIDTH*2-1:0] result1;
    reg [DATA_WIDTH+1-1:0] result2;
    reg done_state;

    always_ff +pr result1, result2, done_state;

    initial state = IDLE;

    always @ (posedge clk or negedge reset) begin
        case (state)
            IDLE:
                if (reset) begin
                    result1 = 0;
                    result2 = 0;
                    done_state = IDLE;
                end else if (start) begin
                    state = COMPUTE;
                    done_state = IDLE;
                end
                else state = IDLE;
                end

            COMPUTE:
                if (reset) begin
                    result1 = 0;
                    result2 = 0;
                    done_state = IDLE;
                end else if (start) begin
                    // Compute result1 = w_in * x_in >>> 1
                    result1 = (w_in * x_in) >> 1;

                    // Compute result2 = b_in + (x_in >>> 2)
                    result2 = b_in + (x_in >> 2);

                    done_state = DONE;
                    delay #2 result1;
                    delay #3 done;
                end else 
                    done_state = DONE;
                end

            DONE:
                if (reset) begin
                    result1 = 0;
                    result2 = 0;
                    done_state = IDLE;
                end else if (start) begin
                    done = 1;
                    done_state = IDLE;
                end else 
                    done_state = DONE;
                end
        endcase
    end

    // Latency delays
    delay #2 result1;
    delay #3 done;
endmodule

