module crossbar_switch #(
    parameter DATA_WIDTH = 8,  // Parameterized data width
    localparam NUM_PORTS = 4,
    localparam DATA_WIDTH_IN = (DATA_WIDTH + $clog2(NUM_PORTS))
)(
    input  logic                        clk,        // Clock signal
    input  logic                        reset,      // Reset signal
    // Input data and destination IDs
    input  logic [DATA_WIDTH_IN-1 :0]  in0, in1, in2, in3,  // Input data
    input  logic                       valid_in0, valid_in1, valid_in2, valid_in3,  // Input data valid
    // Output data
    output logic  [DATA_WIDTH-1:0]      out0, out1, out2, out3,  // Output data
    output logic                        valid_out0, valid_out1, valid_out2, valid_out3  // Output data valid
);
    // Internal Signals
    logic [$clog2(NUM_PORTS)-1 : 0] dest0,dest1,dest2,dest3;           // Destination ID for each input

    // ----------------------------------------
    // - Procedural blocks
    // ----------------------------------------
    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            out0 <= 0;
            out1 <= 0;
            out2 <= 0;
            out3 <= 0;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;
        end else begin
            out0 <= 0 ;
            out1 <= 0 ;
            out2 <= 0 ;
            out3 <= 0 ;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;

            if (valid_in0 == 1) begin
                assign out0 = in0[DATA_WIDTH_IN-1:DATA_WIDTH_IN-2] << (DATA_WIDTH_IN-2);
                valid_out0 = 1;
            end else if (valid_in1 == 1) begin
                assign out1 = in1[DATA_WIDTH_IN-1:DATA_WIDTH_IN-2] << (DATA_WIDTH_IN-2);
                valid_out1 = 1;
            end else if (valid_in2 == 1) begin
                assign out2 = in2[DATA_WIDTH_IN-1:DATA_WIDTH_IN-2] << (DATA_WIDTH_IN-2);
                valid_out2 = 1;
            end else if (valid_in3 == 1) begin
                assign out3 = in3[DATA_WIDTH_IN-1:DATA_WIDTH_IN-2] << (DATA_WIDTH_IN-2);
                valid_out3 = 1;
            end else begin
                out0 <= 0;
                out1 <= 0;
                out2 <= 0;
                out3 <= 0;
            end
        end
    end

    // ----------------------------------------
    // - Combinational Assignments
    // ----------------------------------------
    assign dest0 = in0 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in0 data
    assign dest1 = in1 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in1 data
    assign dest2 = in2 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in2 data
    assign dest3 = in3 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in3 data

endmodule

input.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter(
    input clock,
    input reset,
    input data_in,
    input data_valid,
    output data_out,
    output o_data_out_valid
);
    // Internal variables
    reg [127:0] data_out;
    reg [3:0] counter;
    reg [127:0] buffer;
    reg valid;

    // Initialize buffer and counter
    always_comb begin
        buffer = 0;
        counter = 0;
        valid = 0;
    end

    // Process
    always clock positive edge begin
        if (reset) begin
            buffer = 0;
            counter = 0;
            valid = 0;
        end else begin
            if (data_valid) begin
                counter = counter + 1;
                if (counter == 4) begin
                    // Assemble the buffer into data_out
                    data_out = buffer;
                    // Set output valid
                    o_data_out_valid = 1;
                    // Reset buffer and counter
                    buffer = 0;
                    counter = 0;
                end else begin
                    // Shift data into buffer
                    buffer = (data_in << (128 - 32 * counter)) | buffer;
                end
            end
        end
    end
endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input wire [39:0] data_in,
    input wire clock,
    input wire rst_n,
    output reg [39:0] data_out,
    output reg [1:0] dbi_cntrl
);

    // Previous data storage
    reg [19:0] prev_group1, prev_group0;

    // Control signals
    reg [1:0] control1, control0;

    // Bit counters
    reg [19:0] bit_count1, bit_count0;

    // Initialize previous data on first clock cycle
    always_ff (clk, rst_n) prev_group1, prev_group0;

    // Split data into groups
    wire [19:0] group1, group0;
    group1 = data_in[39:20];
    group0 = data_in[19:0];

    // Compare with previous data
    integer i;
    always clocked(clk) begin
        if (rst_n) begin
            prev_group1 = 0;
            prev_group0 = 0;
            bit_count1 = 0;
            bit_count0 = 0;
        end else begin
            // Compare group1
            for (i = 0; i < 20; i++) begin
                if ((group1[i] != prev_group1[i])) bit_count1++;
            end
            control1 = (bit_count1 > 10);

            // Compare group0
            for (i = 0; i < 20; i++) begin
                if ((group0[i] != prev_group0[i])) bit_count0++;
            end
            control0 = (bit_count0 > 10);
        end
    end

    // Generate data_out
    data_out = 0;
    data_out[39:20] = (control1 ? (group1 ^ 1) : group1);
    data_out[19:0] = (control0 ? (group0 ^ 1) : group0);
endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   input wire rst_n,
   input wire clk,
   input wire [39:0] data_in,
   input wire [1:0] dbi_cntrl,
   output wire [39:0] data_out
);

   // Flip-flops to store the two 20-bit groups
   flip_flop data_group1 (data_in[39:20]);
   flip_flop data_group0 (data_in[19:0]);

   // Invert the groups based on the control signal
   if (dbi_cntrl[1])
      data_group1 = ~data_group1;
   if (dbi_cntrl[0])
      data_group0 = ~data_group0;

   // Combine the groups to form the output
   data_out = (data_group1 << 20) | data_group0;

   // Reset all outputs to 0 if rst_n is asserted
   always @* begin
      if (rst_n)
         data_out = 0;
   end

endmodule

output.rtl/decoder_8b10b.sv:
module decoder_8b10b (
    input  logic        clk_in,       // trigger on rising edge
    input  logic        reset_in,     // reset_in, assert HI
    input  logic [9:0]  decoder_in,   // 10bit input
    output logic [7:0]  decoder_out,  // 8bit decoded output
    output logic        control_out   // control char, assert HI for control words
);

logic [9:0] s_in_10b_reg;  
logic [7:0] s_decoder_out; 
logic s_control_out;     

always_ff @(posedge clk_in or posedge reset_in) begin
    if (reset_in) begin
        s_in_10b_reg <= 10'b0000000000;
        s_decoder_out <= 8'b00000000;
        s_control_out <= 1'b0;
    else begin
        s_in_10b_reg <= decoder_in;
        s_decoder_out <= 8'b00000000;
        s_control_out <= 1'b0;

        case (s_in_10b_reg)
        // K.28.0
        10'b0011110100: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.1
        10'b1100001011: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.2
        10'b0011110101: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.3
        10'b1100001010: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.4
        10'b0011110010: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.5
        10'b1100001001: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.6
        10'b0011111010: s_decoder_out = 8'h1C; s_control_out = 1'b1;
        // K.28.7
