    // Stage 4: F3 = 2 - D6, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F3 = TWO - D6;
    end

    assign D7 = F3 * D6;
    assign N7 = F3 * N6;

    reg18 reg_divisor_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D7[26:9]),
        .data_out(D8)
    );

    reg18 reg_dividend_stage5(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N7[26:9]),
        .data_out(N8)
    );

    dff1 ff6(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st5),
        .q     (st6)
    );

    //////////////////////////////////////////////
    // Stage 5: F4 = 2 - D8, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F4 = TWO - D8;
    end

    assign D9 = F4 * D8;
    assign N9 = F4 * N8;

    reg18 reg_divisor_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D9[26:9]),
        .data_out(D10)
    );
    reg18 reg_dividend_stage6(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N9[26:9]),
        .data_out(N10)
    );

    dff1 ff8(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st6),
        .q     (st7)
    );

    //////////////////////////////////////////////
    // Stage 6: F5 = 2 - D10, multiply, register
    //////////////////////////////////////////////
    always_comb begin
        F5 = TWO - D10;
    end

    assign D11 = F5 * D10;
    assign N11 = F5 * N10;

    reg18 reg_divisor_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(D11[26:9]),
        .data_out(D12)
    );
    reg18 reg_dividend_stage7(
        .clk   (clk),
        .reset (~rst_n),
        .data_in(N11[26:9]),
        .data_out(N12)
    );

    dff1 ff9(
        .clk   (clk),
        .reset (~rst_n),
        .d     (st7),
        .q     (st8)
    );


