   always_ff @ (posedge clk) begin
      if (rst) begin
         // On reset, initialize registers
         A_reg <= 'b0;
         B_reg <= 'b0;
         OUT  <= 'b0;
      end else begin
         case (controlpath_state)
            S0: begin
               // In state S0, load input values into registers
               A_reg <= A;
               B_reg <= B;
