            S1: begin
               // In state S1, perform Stein's algorithm steps
               if (A == B) begin
                  // If A == B, output the result
                  OUT  <= A_reg;
               end else if (A > B) begin
                  // If A > B, subtract B from A
                  A_reg <= A_reg - B_reg;
               end else begin
                  // If B > A, subtract A from B
                  B_reg <= B_reg - A_reg;
               end
