input.rtl/hamming_rx.sv:
module hamming_code_receiver (
  input[7:0] data_in,
  output [3:0] data_out
);

  wire c1,c2,c3,error;
  reg[7:0] correct_data;


  assign c3 =  data_in[1] ^ data_in[3] ^ data_in[5] ^ data_in[7];
  assign c2 =  data_in[2] ^ data_in[3] ^ data_in[6] ^ data_in[7];
  assign c1 =  data_in[4] ^ data_in[5] ^ data_in[6] ^ data_in[7];

  assign error = ({c3,c2,c1}==3'b000) ? 1'b0 : 1'b1;

  always@(*)
  begin
    correct_data = 0;
    if(error)
    begin
      correct_data             = data_in;
      correct_data[{c1,c2,c3}] = ~correct_data[{c1,c2,c3}];
    end
    else
    begin
      correct_data             = data_in;
    end
  end

 assign data_out = {correct_data[7],correct_data[6],correct_data[5],correct_data[3]};

endmodule

output.rtl/hamming_tx.sv:
module hamming_tx #(
    parameter DATA_WIDTH       = 64,
    parameter PART_WIDTH      = 4,
    parameter PARITY_BIT      = 3,
    parameter NUM_MODULES     = DATA_WIDTH / PART_WIDTH,
    parameter TOTAL_ENCODED   = NUM_MODULES * (PARITY_BIT + PART_WIDTH + 1)
) (
    input  [DATA_WIDTH-1:0]    data_in,
    output [TOTAL_ENCODED-1:0] data_out
);

    reg [PARITY_BIT + PART_WIDTH + 1 - 1:0] data_out_reg;
    reg [PARITY_BIT - 1:0] parity;
    integer i, j, count, module_index;

    always begin
        module_index = 0;
        count = 0;

        for (i = 0; i < NUM_MODULES; i = i + 1) begin
            // Extract the current module's slice from data_in
            data_out_reg = 0;
            for (j = 0; j < PART_WIDTH; j = j + 1) begin
                data_out_reg = data_out_reg | (data_in[(i * PART_WIDTH) + j] << (TOTAL_ENCODED - (i * (PART_WIDTH + PARITY_BIT + 1) + j)));
            end

            // Process the slice through t_hamming_tx
            t_hamming_tx #(
                DATA_WIDTH = PART_WIDTH,
                PARITY_BIT = PARITY_BIT
            ) instance_hamming_tx(.data_in(data_out_reg >> (TOTAL_ENCODED - (i * (PART_WIDTH + PARITY_BIT + 1)))), .data_out(t_hamming_tx.data_out))
            );

            // Update count and module_index
            count = 0;
            module_index = i + 1;
        end

        // Concatenate the results
        data_out = data_out_reg;
    end
endmodule

module t_hamming_tx #(
    parameter DATA_WIDTH       = 4,
    parameter PARITY_BIT       = 3,
    parameter ENCODED_DATA     = PARITY_BIT + DATA_WIDTH + 1,
    parameter ENCODED_DATA_BIT = $clog2(ENCODED_DATA)
)(
    input  [DATA_WIDTH-1:0]       data_in,
    output  reg[ENCODED_DATA-1:0] data_out
);

    reg [PARITY_BIT-1:0] parity;
    integer i, j, count;
    reg [ENCODED_DATA_BIT:0] pos;

    always @(*) begin
        data_out = {ENCODED_DATA{1'b0}};
        parity   = {PARITY_BIT{1'b0}};
        count    = 0;

        for (pos = 1; pos < ENCODED_DATA; pos = pos + 1) begin
            if (count < DATA_WIDTH) begin
                if ((pos & (pos - 1)) != 0) begin
                    data_out[pos] = data_in[count];
                    count = count + 1;
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            for (i = 1; i <= ENCODED_DATA-1; i = i + 1) begin
                if ((i & (1 << j)) != 0) begin
                    parity[j] = parity[j] ^ data_out[i];
                end
            end
        end

        for (j = 0; j < PARITY_BIT; j = j + 1) begin
            data_out[(1 << j)] = parity[j];
        end
    end
endmodule

input.rtl/hebb_gates.sv:
module hebb_gates(
   input  logic               clk,
   input  logic               rst,
   input  logic               start, // To start the FSM
   input  logic  signed [3:0] a, // First Input
   input  logic  signed [3:0] b, // Second Input
   input  logic         [1:0] gate_select, // To provide the targets for a selected gate in order to train
   output logic  signed [3:0] w1, // Weight 1 obtained by training
   output logic  signed [3:0] w2, // Weight 2 obtained by training
   output logic  signed [3:0] bias,// Bias obtained by training
   output logic [3:0] present_state,// Present State of the Training FSM
   output logic [3:0] next_state // Next_State of the Training FSM

);
   logic signed [3:0] t1;
   logic signed [3:0] t2;
   logic signed [3:0] t3;
   logic signed [3:0] t4;

   gate_target dut(
       .gate_select(gate_select),
       .o_1        (t1),
       .o_2        (t2),
       .o_3        (t3),
       .o_4        (t4)
   );

   localparam [3:0] S0 = 4'd0;
   localparam [3:0] S1 = 4'd1;
   localparam [3:0] S2 = 4'd2;
   localparam [3:0] S3 = 4'd3;
   localparam [3:0] S4 = 4'd4;
   localparam [3:0] S5 = 4'd5;
   localparam [3:0] S6 = 4'd6;
   localparam [3:0] S7 = 4'd7;
   localparam [3:0] S8 = 4'd8;
   localparam [3:0] S9 = 4'd9;
   localparam [3:0] S10 = 4'd10;

   logic [2:0] iteration;
   logic signed [3:0] x1;
   logic signed [3:0] x2;
   logic signed [3:0] delta_w1;
   logic signed [3:0] delta_w2;
   logic signed [3:0] delta_b;
   logic signed [3:0] w1_reg;
   logic signed [3:0] w2_reg;
   logic signed [3:0] bias_reg;
   logic signed [1:0] target;
   logic delta_en;
   logic sum_en;
   logic clr_en;
   logic cap_en;

   always_comb begin
     if(cap_en ) begin
        x1 = a;
        x2 = b;
     end else begin
        x1 = x1 + 4'h0;
        x2 = x2 + 4'h0;
     end

   end

   always_comb begin

     if(delta_en) begin
       delta_w1 = x1 * target;
       delta_w2 = x2 * target;
       delta_b  = target;
     end else begin
       delta_w1 = delta_w1 + 4'h0;
       delta_w2 = delta_w2 + 4'h0;
       delta_b  = delta_b + 4'h0; 
   end

  end

  always_comb begin

     if(sum_en) begin
       w1_reg = w1_reg + delta_w1;
       w2_reg = w2_reg + delta_w2;
       bias_reg = bias_reg + delta_b;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0;
   end
  end

   always_comb begin

     if(clr_en) begin
       w1_reg = 0;
       w2_reg = 0;
       bias_reg = 0;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0; 
    end
   end

   always_ff@(posedge clk or negedge rst) begin
       if(!rst) begin
          present_state <= S0;
          iteration <= 0;
        end else
          present_state <= next_state;
   end

   always_comb begin
        next_state = present_state;

     case(present_state)
             S0  : begin 
                      if(start)
                         next_state = S1;
                      else
                         next_state = S0;
                   end
             S1  : begin 
                         next_state = S2;
                   end
             S2  : begin 
                      if(iteration == 0)
                        next_state = S3;
                     else if(iteration == 1)
                        next_state = S4;
                     else if(iteration == 2)
                        next_state = S5;
                     else 
                        next_state = S6;
                   end
             S3  : begin 
                         next_state = S7;

                   end
             S4  : begin 
                         next_state = S7;
                  end
             S5  : begin 
                         next_state = S7;
                  end
             S6  : begin 
                         next_state = S7;
                  end
             S7  :begin
                         next_state = S8;
                  end
             S8  : begin
                         next_state = S9;
                  end
             S9  : begin
                      if(iteration < 4)
                         next_state = S1;
                      else
                         next_state = S10;
                   end
             S10 : begin
                      next_state = S0;
                   end
             default : ;
     endcase
   end 

   always_comb begin

      case(present_state)
             S0 : begin
                    clr_en = 1;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en   = 0;
                    iteration = 0;
                    target = target + 4'h0;
                  end 
             S1 : begin
                    clr_en = 0;
                    cap_en = 1;
                    delta_en = 0;
                    sum_en = 0;  
                    iteration = iteration + 0;  
                    target = target + 4'h0;              
                  end
             S2 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0; 
                    iteration = iteration + 0;     
                    target = target + 4'h0;              
                  end
             S3 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t1;
                  end
             S4 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t2;
                  end     

             S5 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t3;
                  end  
             S6 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = t4;
                  end        
             S7 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 1;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end
             S8 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 1;
                    iteration = iteration + 1;
                    target = target + 4'h0;
                  end
             S9 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end  
             S10 : begin
                    clr_en = 0;
                    cap_en = 0;
                    delta_en = 0;
                    sum_en = 0;
                    iteration = iteration + 0;
                    target = target + 4'h0;
                  end



           default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
       endcase
   end
   assign w1 = w1_reg;
   assign w2 = w2_reg;
   assign bias = bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

output.rtl/hebb_gates.sv:
module hebb_gates(
   input  logic  clk,
   input  logic rst,
   input  logic start,
   input  logic  signed [3:0] a,
   input  logic  signed [3:0] b,
   input  logic   [1:0] gate_select,
   output logic  signed [3:0] w1,
   output logic  signed [3:0] w2,
   output logic  signed [3:0] bias,
   output logic [3:0] present_state,
   output logic [3:0] next_state
);

   logic signed [3:0] t1, t2, t3, t4;
   logic signed [3:0] x1, x2;
   logic signed [3:0] delta_w1, delta_w2, delta_b;
   logic signed [3:0] w1_reg, w2_reg, bias_reg;
   logic [3:0] x1_reg, x2_reg;
   logic [3:0] delta_w1_reg, delta_w2_reg, delta_b_reg;
   logic signed [3:0] w1_new, w2_new, b_new;
   logic [3:0] iteration;
   logic signed [3:0] target;
   logic [3:0] present_state;
   logic [3:0] next_state;

   // Testing FSM signals
   logic [4:3] test_present_state;
   logic signed [3:0] test_output;
   logic signed [3:0] test_result;
   logic test_done;
   logic [4:3] test_index;

   // Test vectors
   parameter [15:0] test_inputs_x1 = {4'd0, 4'd1, 4'd2, 4'd3, 4'd4, 4'd5, 4'd6, 4'd7, 4'd8, 4'd9, 4'd10, 4'd11, 4'd12, 4'd13, 4'd14, 4'd15};
   parameter [15:0] test_inputs_x2 = {4'd0, 4'd1, 4'd2, 4'd3, 4'd4, 4'd5, 4'd6, 4'd7, 4'd8, 4'd9, 4'd10, 4'd11, 4'd12, 4'd13, 4'd14, 4'd15};
   parameter [15:0] test_expected_outputs = {4'd0, 4'd1, 4'd2, 4'd3, 4'd4, 4'd5, 4'd6, 4'd7, 4'd8, 4'd9, 4'd10, 4'd11, 4'd12, 4'd13, 4'd14, 4'd15};

   // State Machine for Training FSM
   always_comb begin
     if(cap_en) begin
        x1 = a;
        x2 = b;
     end else begin
        x1 = x1 + 4'h0;
        x2 = x2 + 4'h0;
     end

     if(delta_en) begin
        delta_w1 = x1 * target;
        delta_w2 = x2 * target;
        delta_b  = target;
     end else begin
        delta_w1 = delta_w1 + 4'h0;
        delta_w2 = delta_w2 + 4'h0;
        delta_b  = delta_b + 4'h0;
     end

     if(sum_en) begin
        w1_reg = w1_reg + delta_w1;
        w2_reg = w2_reg + delta_w2;
        bias_reg = bias_reg + delta_b;
     end else begin
        w1_reg = w1_reg + 4'h0;
        w2_reg = w2_reg + 4'h0;
        bias_reg = bias_reg + 4'h0;
     end

     if(clr_en) begin
        w1_reg = 0;
        w2_reg = 0;
        bias_reg = 0;
     end else begin
        w1_reg = w1_reg + 4'h0;
        w2_reg = w2_reg + 4'h0;
        bias_reg = bias_reg + 4'h0;
     end
  end

  // State Machine for Testing FSM
  always_comb begin
     // State Transitions
     case(test_present_state)
        S0_test: begin
            test_index = (gate_select == 2'b00) ? 4'd0 : 
                        (gate_select == 2'b01) ? 4'd4 : 
                        (gate_select == 2'b10) ? 4'd8 : 
                        (gate_select == 2'b11) ? 4'd12 : 4'd0;
            test_x1 = test_inputs_x1[test_index];
            test_x2 = test_inputs_x2[test_index];
            test_expected_output = test_expected_outputs[test_index];
            test_calc = (w1 * test_x1) + (w2 * test_x2) + bias;
            test_output = (test_calc > 0) ? 4'd1 : 4'd-1;
            test_result = (test_output == test_expected_output) ? 4'b1000 : 4'b0000;
            test_done = 0;
            test_present_state = S1_test;
        end

        S1_test: begin
            test_index = test_index + 1;
            test_x1 = test_inputs_x1[test_index];
            test_x2 = test_inputs_x2[test_index];
            test_expected_output = test_expected_outputs[test_index];
            test_calc = (w1 * test_x1) + (w2 * test_x2) + bias;
            test_output = (test_calc > 0) ? 4'd1 : 4'd-1;
            test_result = (test_output == test_expected_output) ? 4'b1000 : 4'b0000;
            test_done = (test_index == 16) ? 1 : 0;
            test_present_state = S2_test;
        end

        S2_test: begin
            test_x1 = test_inputs_x1[test_index];
            test_x2 = test_inputs_x2[test_index];
            test_expected_output = test_expected_outputs[test_index];
            test_calc = (w1 * test_x1) + (w2 * test_x2) + bias;
            test_output = (test_calc > 0) ? 4'd1 : 4'd-1;
            test_result = (test_output == test_expected_output) ? 4'b1000 : 4'b0000;
            test_done = (test_index == 16) ? 1 : 0;
            test_present_state = S3_test;
        end

        S3_test: begin
            test_x1 = test_inputs_x1[test_index];
            test_x2 = test_inputs_x2[test_index];
            test_expected_output = test_expected_outputs[test_index];
            test_calc = (w1 * test_x1) + (w2 * test_x2) + bias;
            test_output = (test_calc > 0) ? 4'd1 : 4'd-1;
            test_result = (test_output == test_expected_output) ? 4'b1000 : 4'b0000;
            test_done = (test_index == 16) ? 1 : 0;
            test_present_state = S4_test;
        end

        S4_test: begin
            test_x1 = test_inputs_x1[test_index];
            test_x2 = test_inputs_x2[test_index];
            test_expected_output = test_expected_outputs[test_index];
            test_calc = (w1 * test_x1) + (w2 * test_x2) + bias;
            test_output = (test_calc > 0) ? 4'd1 : 4'd-1;
            test_result = (test_output == test_expected_output) ? 4'b1000 : 4'b0000;
            test_done = (test_index == 16) ? 1 : 0;
            test_present_state = S0_test;
        end
     endcase
  end

  // FSM State Transitions
  always_comb begin
     if(delta_en) begin
        delta_w1 = x1 * target;
        delta_w2 = x2 * target;
        delta_b  = target;
     end else begin
        delta_w1 = delta_w1 + 4'h0;
        delta_w2 = delta_w2 + 4'h0;
        delta_b  = delta_b + 4'h0;
     end

     if(sum_en) begin
        w1_reg = w1_reg + delta_w1;
        w2_reg = w2_reg + delta_w2;
        b_new = b_new + delta_b;
     end else begin
        w1_reg = w1_reg + 4'h0;
        w2_reg = w2_reg + 4'h0;
        b_new = b_new + 4'h0;
     end

     if(clr_en) begin
        w1_reg = 0;
        w2_reg = 0;
        b_new = 0;
     end else begin
        w1_reg = w1_reg + 4'h0;
        w2_reg = w2_reg + 4'h0;
        b_new = b_new + 4'h0;
     end

     if(!rst) begin
        present_state <= S0;
        iteration <= 0;
        target <= 4'd0;
     end else
        present_state <= next_state;
  end
endmodule

module hebbian_rule(
    input clock,
    input rst,
    input start,
    input [3:0] a,
    input [3:0] b,
    input [1:0] gate_select,
    output [3:0] w1,
    output [3:0] w2,
    output [3:0] bias,
    output [3:0] present_state,
    output next_state
);

    // State variable
    reg state = 0;

    // State-specific registers
    reg [3:0] x1, x2;
    reg [3:0] temp_w1, temp_w2;
    reg [3:0] temp_bias;
    reg [3:0] target;
    reg [3:0] delta_w1, delta_w2, delta_b;

    // Initialize weights and bias to zero
    always @* begin
        x1 = a;
        x2 = b;
        temp_w1 = 0;
        temp_w2 = 0;
        temp_bias = 0;
    end

    // State transitions and logic
    case(state)
        // State 0: Reset state
        0: 
            if (rst == 1 && start == 1) begin
                state = 0;
                present_state = 0;
                next_state = 0;
                // Initialize weights and bias
                w1 = 0;
                w2 = 0;
                bias = 0;
                // Capture inputs
                x1 = a;
                x2 = b;
                // Compute target based on gate select
                case(gate_select)
                    00: target = a & b;
                    01: target = a | b;
                    10: target = ~(a & b);
                    11: target = ~(a | b);
                endcase
                // Calculate deltas
                delta_w1 = x1 & target;
                delta_w2 = x2 & target;
                delta_b = target;
                // Update weights and bias
                w1 = w1 + delta_w1;
                w2 = w2 + delta_w2;
                bias = bias + delta_b;
                // Prepare for next iteration
                state = 1;
                present_state = 0;
                next_state = 0;
            end
            // Negative edge transition
            default: state = 1;
    end

        // State 1: Capture inputs
        1: 
            // Compute deltas
            delta_w1 = x1 & target;
            delta_w2 = x2 & target;
            delta_b = target;
            // Update weights and bias
            temp_w1 = w1 + delta_w1;
            temp_w2 = w2 + delta_w2;
            temp_bias = bias + delta_b;
            // Transition to next state
            next_state = 2;
            present_state = 1;
            // Negative edge transition
            default: next_state = 2;

        // State 2: Assign targets
        2: 
            // Transition to next state
            next_state = 3;
            present_state = 2;
            // Negative edge transition
            default: next_state = 3;

        // State 3: Compute deltas
        3: 
            // Transition to next state
            next_state = 4;
            present_state = 3;
            // Negative edge transition
            default: next_state = 4;

        // State 4: Update weights and bias
        4: 
            // Update weights and bias
            w1 = temp_w1;
            w2 = temp_w2;
            bias = temp_bias;
            // Transition to next state
            next_state = 5;
            present_state = 4;
            // Negative edge transition
            default: next_state = 5;

        // State 5: Loop through iterations
        5: 
            // Transition to next state
            next_state = 0;
            present_state = 5;
            // Negative edge transition
            default: next_state = 0;

    endcase

    // Output the updated weights and bias
    output_w1: w1 = temp_w1;
    output_w2: w2 = temp_w2;
    output_bias: bias = temp_bias;

endmodule

