module palindrome_detect #( 
parameter N=3
) (
input clk,
input reset,
input bit_stream,
output palindrome_detected
);

  wire [N-1:0] bit_FIFO;
  integer i;

  initial begin
    i = 0;
    bit_FIFO = { {3'b0}, {3'b0}, {3'b0} };
  end

  forever begin
    if (reset) begin
      bit_FIFO = { {3'b0}, {3'b0}, {3'b0} };
      palindrome_detected = 0;
      sleep(10);
    end else begin
      bit_FIFO = { bit_FIFO[2], bit_stream };
      if (bit_FIFO[0] == bit_FIFO[2]) begin
        palindrome_detected = 1;
      else begin
        palindrome_detected = 0;
      end
    end
    sleep(10);
  end
endmodule

output.rtl/password_generator.sv:
module password_generator #(
    parameter WIDTH = 4  
) (
    input logic clk,
    input logic reset,
    output logic [(WIDTH*8)-1:0] password 
);

  logic [7:0] char_array[WIDTH-1:0];  
  logic [7:0] counter;  
  logic [1:0] char_type; 

  int i;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      counter = 0;
      password = 0;
      return;
    end
    // Counter increment with carry
    if (counter == 255) begin
      counter = 0;
      carry = 0;
    else
      carry = 1;
    end
    counter = counter + carry;
  end

  // Generate password characters
  always begin
    for (i = 0; i < WIDTH; i = i + 1) begin
      case (char_type)
        00: // Lowercase letters
          password[(i * 8):7] = ((counter + char_array[(i + 1) % WIDTH]) % 26) + 8'h97;
          break;
        01: // Uppercase letters
          password[(i * 8):7] = ((counter + i) % 26) + 8'h65;
          break;
        10: // Special characters
          password[(i * 8):7] = ((counter + char_array[(i + WIDTH - 1) % WIDTH]) % 14) + 8'h33;
          break;
        11: // Numeric digits
          password[(i * 8):7] = ((counter + i) % 10) + 8'h48;
          break;
        default: 
          password[(i * 8):7] = 0;
          break;
      endcase
    end
  end
  endmodule

output.rtl/perceptron_gates.sv:
module perceptron_gates(
    input clock,
    input rst_n,
    input [3:0] x1,
    input [3:0] x2,
    input [1:0] learning_rate,
    input [3:0] threshold,
    input [1:0] gate_select
    output [3:0] percep_w1,
    output [3:0] percep_w2,
    output [3:0] percep_bias,
    output [1:0] stop,
    output [2:0] input_index,
    output [3:0] prev_percep_wt_1,
    output [3:0] prev_percep_wt_2,
    output [3:0] prev_percep_bias
);

    // Microcode ROM definition
    reg [3:0] microcode_rom [6:0];

    // State variable for microcode execution
    reg present_addr;

    // Always block to load initial microcode
    always clock falling edge, rst_n inactive high:
        present_addr = 4'd0;
        microcode_rom[0] = 4'b0000;
        microcode_rom[1] = 4'b0001;
        microcode_rom[2] = 4'b0010;
        microcode_rom[3] = 4'b0011;
        microcode_rom[4] = 4'b0100;
        microcode_rom[5] = 4'b0101;

    // State transition logic
    always clock falling edge:
        if (rst_n) begin
            present_addr = 4'd0;
        else
            present_addr = present_addr + 1;
            if (present_addr >= 6) present_addr = 4'd0;
        end

    // Microcode execution
    always clock falling edge:
        case (present_addr)
            4'd0: begin
                // Action 0: Initialize weights and bias to zero
                percep_w1 = 4'd1;
                percep_w2 = 4'd1;
                percep_bias = 4'd1;
                present_addr = 4'd1;
                // Update previous weights and bias
                prev_percep_wt_1 = percep_w1;
                prev_percep_wt_2 = percep_w2;
                prev_percep_bias = percep_bias;
            end

            4'd1: begin
                // Action 1: Compute perceptron output
                y_in = (x1 & percep_w1) + (x2 & percep_w2) + percep_bias;
                y = y_in > (threshold >> 2) ? 4'd1 : 4'd-1;
                present_addr = 4'd2;
                // Update previous outputs
                prev_percep_wt_1 = y_in;
                prev_percep_wt_2 = y;
                prev_percep_bias = y;
            end

            4'd2: begin
                // Action 2: Select target based on gate type and input index
                case (gate_select)
                    2'b00: target = 4'd1;
                    2'b01: target = (x1 & x2) ? 4'd1 : 4'd-1;
                    2'b10: target = (x1 | x2) ? 4'd1 : 4'd-1;
                    2'b11: target = 4'd-1;
                endcase
                present_addr = 4'd3;
                // Update previous target
                prev_percep_wt_1 = target;
            end

            4'd3: begin
                // Action 3: Update weights and bias if needed
                wt1_update = (y != target) ? (learning_rate & x1) : 4'd0;
                wt2_update = (y != target) ? (learning_rate & x2) : 4'd0;
                bias_update = (y != target) ? learning_rate : 4'd0;

                // Apply updates
                percep_w1 = percep_w1 + wt1_update;
                percep_w2 = percep_w2 + wt2_update;
                percep_bias = percep_bias + bias_update;

                // Update previous weights and bias
                prev_percep_wt_1 = wt1_update;
                prev_percep_wt_2 = wt2_update;
                prev_percep_bias = bias_update;
                present_addr = 4'd4;
            end

            4'd4: begin
                // Action 4: Check for convergence
                if (wt1_update == 4'd0 && wt2_update == 4'd0 && bias_update == 4'd0) begin
                    stop = 1;
                    present_addr = 4'd5;
                end
                present_addr = 4'd5;
            end

            4'd5: begin
                // Action 5: Finalize updates and prepare next epoch
                percep_w1 = percep_w1 + prev_percep_wt_1;
                percep_w2 = percep_w2 + prev_percep_wt_2;
                percep_bias = percep_bias + prev_percep_bias;
                present_addr = 4'd0;
            end
        end

    // Always block to handle input index
    always clock falling edge:
        if (rst_n) begin
            input_index = 4'd0;
        else
            input_index = input_index + 1;
            if (input_index >= 4) input_index = 4'd0;
        end

endmodule

input.rtl/perceptron_gates.sv:
module perceptron_gates (
   input  logic clk,// Posedge clock
   input  logic rst_n,// Negedge reset
   input  logic signed [3:0] x1, // First Input of the Perceptron
   input  logic signed [3:0] x2, // Second Input of the Perceptron
   input  logic learning_rate, // Learning rate (alpha)
   input  logic signed [3:0] threshold, // Threshold value
   input  logic [1:0] gate_select, // Gate selection for target values
   output logic signed [3:0] percep_w1, // Trained Weight 1 
   output logic signed [3:0] percep_w2, // Trained Weight 2
   output logic signed [3:0] percep_bias, // Trained Bias
   output logic [3:0] present_addr, // Current address in microcode ROM
   output logic stop, // Condition to indicate no learning has occurred(i.e. no weight change between iterations)
   output logic [2:0] input_index,// Vector to track the selection of target for a given input combination for a gate
   output logic signed [3:0] y_in, // Calculated Response
   output logic signed [3:0] y, // Calculated Response obtained by comparing y_in against a threshold value
   output logic signed [3:0] prev_percep_wt_1,//Value of Weight 1 during a previous iteration
   output logic signed [3:0] prev_percep_wt_2,//Value of Weight 2 during a previous iteration
   output logic signed [3:0] prev_percep_bias // Value of Bias during a previous iteration
);

   logic [15:0] microcode_rom [0:5];
   logic [3:0]  next_addr;
   logic [3:0]  train_action;
   logic [3:0]  microcode_addr;
   logic [15:0] microinstruction;
   logic signed [3:0] t1, t2, t3, t4;

   gate_target dut (
       .gate_select(gate_select),
       .o_1(t1),
       .o_2(t2),
       .o_3(t3),
       .o_4(t4)
   );

   logic signed [3:0] percep_wt_1_reg;
   logic signed [3:0] percep_wt_2_reg;
   logic signed [3:0] percep_bias_reg;


   logic signed [3:0] target;
   logic signed [3:0] prev_wt1_update;
   logic signed [3:0] prev_wt2_update;
   logic signed [3:0] prev_bias_update;

   logic signed [3:0] wt1_update;
   logic signed [3:0] wt2_update;
   logic signed [3:0] bias_update;
   logic [7:0] epoch_counter;

   assign  prev_percep_wt_1 = prev_wt1_update;
   assign  prev_percep_wt_2 = prev_wt2_update;
   assign  prev_percep_bias = prev_bias_update;

   initial begin 
      microcode_rom[0] = 16'b0001_0000_0000_0000; 
      microcode_rom[1] = 16'b0010_0001_0000_0000; 
      microcode_rom[2] = 16'b0011_0010_0000_0000; 
      microcode_rom[3] = 16'b0100_0011_0000_0000; 
      microcode_rom[4] = 16'b0101_0100_0000_0000; 
      microcode_rom[5] = 16'b0000_0101_0000_0000; 
   end  

   always@(*) begin
      microinstruction = microcode_rom[microcode_addr];
      next_addr        = microinstruction[15:12];
      train_action     = microinstruction[11:8];
   end

   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         present_addr    <= 4'd0;
         microcode_addr  <= 4'd0;
         percep_wt_1_reg <= 4'd0;
         percep_wt_2_reg <= 4'd0;
         percep_bias_reg <= 4'd0;
         input_index     <= 2'd0;
         stop            <= 1'b0;
      end else begin
         present_addr    <= next_addr;
         microcode_addr  <= present_addr;
      end
   end

   always_comb begin
      case (train_action)
         4'd0:  begin 
                   percep_wt_1_reg = 4'd0;
                   percep_wt_2_reg = 4'd0;
                   percep_bias_reg = 4'd0;
                   stop = 1'b0;
                   next_addr = next_addr + 4'd0;
                   y_in = 4'd0;
                   y    = 4'd0;
                   prev_wt1_update = 4'd0;
                   prev_wt2_update = 4'd0;
                   prev_bias_update = 4'd0;
                   input_index = 0;
                   target = 0;
                   wt1_update = 0;
                   wt2_update = 0;
                   bias_update = 0;
                   epoch_counter = 0;
                end
         4'd1 : begin 
                   y_in = percep_bias_reg + (x1 * percep_wt_1_reg) + (x2 * percep_wt_2_reg); 
                   if (y_in > threshold)
                      y = 4'd1;
                   else if (y_in >= -threshold && y_in <= threshold)
                      y = 4'd0;
                   else
                      y = -4'd1;

                   percep_wt_1_reg  = percep_wt_1_reg  + 4'd0;
                   percep_wt_2_reg  = percep_wt_2_reg  + 4'd0;
                   percep_bias_reg  = percep_bias_reg  + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   stop = stop + 1'b0;
                   target = target + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd2 : begin
                   if(input_index == 0)
                        target = t1;
                   else if(input_index == 1)
                        target = t2;
                   else if(input_index == 2)
                        target = t3;
                   else if(input_index == 3)
                        target = t4;
                   else begin
                        input_index = 0;
                        target = 0;
                   end
                   stop = stop + 1'b0;
                   input_index = input_index + 0;
                   next_addr = next_addr + 4'd0;
                   target = target + 4'd0;
                   prev_wt1_update  = prev_wt1_update  + 4'd0;
                   prev_wt2_update  = prev_wt2_update  + 4'd0;
                   prev_bias_update = prev_bias_update + 4'd0;

                   percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                   percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                   percep_bias_reg = percep_bias_reg + 4'd0;
                   y_in = y_in + 4'd0;
                   y = y + 4'd0;
                   wt1_update = wt1_update + 4'd0 ;
                   wt2_update = wt2_update + 4'd0 ;
                   bias_update = bias_update + 4'd0 ;
                   epoch_counter = epoch_counter + 0;
                end
         4'd3 : begin
                   if (y != target) begin
                        wt1_update = learning_rate * x1 * target ;
                        wt2_update = learning_rate * x2 * target ;
                        bias_update = learning_rate * target ; 
                    end else begin
                        wt1_update = 0 ;
                        wt2_update = 0 ;
                        bias_update = 0 ;     
                    end    
                    percep_wt_1_reg = percep_wt_1_reg + wt1_update;
                    percep_wt_2_reg = percep_wt_2_reg + wt2_update;
                    percep_bias_reg = percep_bias_reg + bias_update;
                    prev_wt1_update  = prev_wt1_update  + 4'd0;
                    prev_wt2_update  = prev_wt2_update  + 4'd0;
                    prev_bias_update = prev_bias_update + 4'd0;
                    y_in = y_in + 4'd0;
                    y = y + 4'd0;
                    stop = stop + 1'b0;
                    input_index = input_index + 0;
                    next_addr = next_addr + 4'd0;
                    target = target + 4'd0;
                    epoch_counter = epoch_counter + 0;
                end
         4'd4 : begin
                  if ((prev_wt1_update == wt1_update) & (prev_wt2_update == wt2_update) & (input_index == 4'd3)) begin 
                          epoch_counter = 0;
                          stop = 1'b1; 
                          input_index = 0;
                          next_addr = 4'd0;
                          percep_wt_1_reg = 0;
                          percep_wt_2_reg = 0;
                          percep_bias_reg = 0;
                          prev_wt1_update =  0;
                          prev_wt2_update =  0;
                          prev_bias_update = 0;
                          y_in = 0;
                          y = 0;
                          target = 0;
                          wt1_update = 0 ;
                          wt2_update = 0 ;
                          bias_update = 0 ;
                  end else begin
                          stop = 1'b0; 
                          input_index = input_index + 0;
                          epoch_counter = epoch_counter + 1;    
                          next_addr = 4'd5;    
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                  end
                end
         4'd5 : begin
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update  = wt1_update;
                          prev_wt2_update  = wt2_update;
                          prev_bias_update = bias_update;
                          next_addr = 4'd1;
                          input_index = input_index + 1;
                          stop = stop + 1'b0;
                          epoch_counter = epoch_counter + 0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0;
                          wt2_update = wt2_update + 4'd0;
                          bias_update = bias_update + 4'd0;
                end   
      default : begin
                          next_addr = next_addr + 4'd0;
                          percep_wt_1_reg = percep_wt_1_reg + 4'd0;
                          percep_wt_2_reg = percep_wt_2_reg + 4'd0;
                          percep_bias_reg = percep_bias_reg + 4'd0;
                          prev_wt1_update = prev_wt1_update + 4'd0;
                          prev_wt2_update = prev_wt2_update + 4'd0;
                          prev_bias_update = prev_bias_update + 4'd0;
                          stop = stop + 1'b0;
                          y_in = y_in + 4'd0;
                          y = y + 4'd0;
                          input_index = input_index + 0;
                          target = target + 4'd0;
                          wt1_update = wt1_update + 4'd0 ;
                          wt2_update = wt2_update + 4'd0 ;
                          bias_update = bias_update + 4'd0 ;
                          epoch_counter = epoch_counter + 0;
                end
      endcase
   end
   assign percep_w1 = percep_wt_1_reg;
   assign percep_w2 = percep_wt_2_reg;
   assign percep_bias = percep_bias_reg;

endmodule

module gate_target(
   input  logic        [1:0] gate_select,
   output logic signed [3:0] o_1,
   output logic signed [3:0] o_2,
   output logic signed [3:0] o_3,
   output logic signed [3:0] o_4
);
   always_comb begin
     case(gate_select)
          2'b00 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
          2'b01 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b10 : begin 
                    o_1 =  1; 
                    o_2 =  1; 
                    o_3 =  1; 
                    o_4 = -1; 
                  end
          2'b11 : begin 
                    o_1 =  1; 
                    o_2 = -1; 
                    o_3 = -1; 
                    o_4 = -1; 
                  end
        default : begin
                    o_1 =  0; 
                    o_2 =  0; 
                    o_3 =  0; 
                    o_4 =  0; 
                  end
        endcase
   end
endmodule

