module dual_port_memory (
    input logic clk,
    input logic we,
    input logic [7:0] write_addr,
    input logic [7:0] din,
    input logic [7:0] read_addr,
    output logic [7:0] dout
);

    logic [7:0] mem [255:0];

    always_ff @(posedge clk) begin
        if (we) begin
            mem[write_addr] <= din;
        end
    end

    assign dout = mem[read_addr];
endmodule

output.rtl/pipeline_mac.sv:
module pipeline_mac #(
    parameter DWIDTH = 16,
    parameter N = 4
) (
    clk,
    rstn,
    multiplicand,
    multiplier,
    valid_i,
    result,
    valid_out
);
  // Calculate accumulator width to handle potential overflow
  parameter DWIDTH_ACCUMULATOR = 2 * DWIDTH; // Sufficient width for accumulation

  logic [DWIDTH_ACCUMULATOR-1:0] mult_result_reg;
  logic [DWIDTH_ACCUMULATOR-1:0] accumulation_reg;
  logic [$clog2(N):0] counter;
  logic [$clog2(N):0] counter_reg;
  logic count_rst, accumulator_rst;

  always @(posedge clk or negedge rstn) begin
    // Multiplication stage
    if (valid_i & ~rstn) begin
      mult_result_reg = multiplicand * multiplier;
    end
    // Store intermediate result
    accumulation_reg = mult_result_reg;
  end

  always @(posedge clk or negedge rstn) begin
    // Accumulation stage
    if (valid_i & ~rstn) begin
      accumulation_reg = accumulation_reg + accumulation_reg;
    end
    // Store final result
    result = accumulation_reg;
  end

  always @(posedge clk or negedge rstn) begin
    // Counter logic
    counter = count_rst ? 'b1 : (valid_i & rstn ? (counter_reg + 'd1) : counter_reg);
    count_rst = valid_out_s1;
    accumulator_rst = valid_out_s1;
  end

  always @(posedge clk or negedge rstn) begin
    // Valid output logic
    valid_out_s0 = (counter_reg == N-1);
    valid_out_s1 = valid_out_s0 & ~valid_out_s2;
    valid_out_s2 = valid_out_s1 & ~valid_out;
    valid_out = valid_out_s1 & ~valid_out_s2;
  end

  assign result = accumulation_reg;
  assign valid_out = valid_out_s1 & ~valid_out_s2;
endmodule

output.rtl/piso_8bit.sv:
module piso_8bit (
    input clock,
    input rst,
    output serial_out
);

    // Internal state variables
    reg [7:0] shift_reg;
    reg tmp;
    reg [7:0] counter;

    // Initialize the shift register with the initial value
    initial begin
        shift_reg = 0b00000001;
        tmp = 0b00000001;
        counter = 0;
    end

    // Process block
    always_comb begin
        // When reset is active LOW, reset the shift register and tmp
        if (rst == 1)
            shift_reg = tmp;
            counter = 0;
        else
            // Increment counter on each clock cycle
            counter = counter + 1;
            // When counter reaches 8, increment tmp and reset counter
            if (counter == 8)
                begin
                    tmp = tmp + 1;
                    counter = 0;
                end
            // Shift the shift register right by 1 bit
            shift_reg = (shift_reg >> 1);
            // The serial_out is the MSB of the shift register
            serial_out = shift_reg[7];
    end
endmodule

