module round_robin_arbiter #(
    parameter N = 4
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;

    integer i;
    always @(*) begin
        grant        = {N{1'b0}};
        pointer_next = pointer;

        if (req != 0) begin
           found = 1'b0;
            for (i = 0; i < N; i = i + 1) begin
                if (!found && req[(pointer + i) % N] == 1'b1) begin
                    grant[(pointer + i) % N] = 1'b1;

                    pointer_next = (pointer + i + 1) % N;
                    found        = 1'b1;                    
                end
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
        end else begin
            pointer <= pointer_next;
        end
    end

endmodule

output.rtl/round_robin_arbiter.sv:
module round_robin_arbiter #(
    parameter N = 4
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    input  wire [N-1:0]     priority_level,
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;
    reg [N-1:0] timeout_counter;

    integer i;
    always @(*) begin
        grant        = {N{1'b0}};
        pointer_next = pointer;
        timeout_counter = {N{32'h0}};

        if (req != 0) begin
            found = 1'b0;
            for (i = 0; i < N; i = i + 1) begin
                if (priority_level[i] & 1) begin
                    if (!found && req[(pointer + i) % N] == 1'b1) begin
                        grant[(pointer + i) % N] = 1'b1;
                        pointer_next = (pointer + i + 1) % N;
                        found        = 1'b1;
                        timeout_counter[(pointer + i) % N] = 32'h0;
                    end
                    else if (timeout_counter[(pointer + i) % N] >= TIMEOUT) begin
                        grant[(pointer + i) % N] = 1'b1;
                        pointer_next = (pointer + i + 1) % N;
                        found        = 1'b1;
                        timeout_counter[(pointer + i) % N] = 32'h0;
                    end
                end
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
            timeout_counter <= {N{32'h0}};
        end else begin
            pointer <= pointer_next;
        end
    end

    output reg idle = 1'b0;
endmodule

output.rtl/copilot_rs_232.sv:
module copilot_rs_232 (
    clock,
    reset_neg,
    tx_datain_ready,
    Present_Processing_Completed,
    tx_datain,
    tx_transmitter,
    tx_transmitter_valid
);
    // Parameters
    parameter HIGH = 1'b1;
    parameter LOW = 1'b0;
    parameter CLOCK_FREQ = 100000000; // 100MHz
    parameter BAUD_RATE = 115200;     // Default baud rate
    parameter REG_INPUT = 1;
    parameter BAUD_ACC_WIDTH = 16;

    // Inputs
    input reset_neg;
    input clock;
    input tx_datain_ready;
    input Present_Processing_Completed;
    input [7:0] tx_datain;

    // Outputs
    output tx_transmitter;
    output tx_transmitter_valid;

    // Internal signals
    reg tx_transmitter;
    reg [3:0] state; // State: 0=Idle, 1=Start, 2=Data, 3=Stop
    wire baud_pulse;

    // Instantiate the Baud Rate Generator
    baud_rate_generator #(
        .BAUD_ACC_WIDTH(BAUD_ACC_WIDTH),
        .CLOCK_FREQ(CLOCK_FREQ),
        .BAUD_RATE(BAUD_RATE)
    ) baud_gen (
        .clock(clock),
        .reset_neg(reset_neg),
        .enable(tx_transmitter_valid),
        .baud_pulse(baud_pulse)
    );

    // State Machine
    always @ (posedge clock or posedge reset_neg) begin
        if (reset_neg == LOW) begin
            state <= 0; // Idle state
        else if (Present_Processing_Completed == HIGH) begin
            state <= 0; // Reset if processing completed
        else if (tx_datain_ready == HIGH) begin
            state <= 1; // Start transmission
        end else if (state == 1) begin
            state <= (state + 1); // Transmit data bits
        end else if (state == 8) begin
            state <= 3; // Stop transmission
        end
    end

    // Output Multiplexer
    always begin
        tx_transmitter_valid <= state; // Output valid when in transmitting state
    end

endmodule

// Baud Rate Generator Module
module baud_rate_generator #(
    parameter CLOCK_FREQ = 100000000, // 100MHz
    parameter BAUD_RATE = 115200, // Default baud rate
    parameter BAUD_ACC_WIDTH = 16
)
 (
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_inc;
    reg [BAUD_ACC_WIDTH:0] baud_acc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Baud rate generator logic
    always @ (posedge clock) begin
        if (enable) begin
            baud_acc <= (baud_acc + baud_inc) & ((1 << BAUD_ACC_WIDTH) - 1);
            if (baud_acc == 0) begin
                baud_pulse <= HIGH;
            end else begin
                baud_pulse <= LOW;
            end
        end else begin
            baud_pulse <= LOW;
        end
    end
endmodule

output.rtl/run_length.sv:
module run_length
#(
    parameter DATA_WIDTH = 8
)
(
    input wire clk,
    input wire reset_n,
    input wire data_in,
    output reg data_out,
    output reg [$clog2(DATA_WIDTH):0] run_value,
    output reg valid
);
    reg [$clog2(DATA_WIDTH):0] run_length;
    reg prev_data_in;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            run_length <= 'b0;
            run_value <= 'b0;
            prev_data_in <= 1'b0;
            valid <= 1'b0;
            data_out <= 1'b0;
        end
        else begin
            if (data_in == prev_data_in) begin
                run_length <= run_length + 1;
            end else begin
                run_length <= 1;
                run_value <= run_length;
                data_out <= prev_data_in;
                valid <= 1'b1;
            end
            if (run_length == DATA_WIDTH) begin
                valid <= 1'b1;
                run_value <= DATA_WIDTH;
            end
            else if (!reset_n) begin
                run_length <= 'b0;
                run_value <= 'b0;
                prev_data_in <= data_in;
            end
        end
    end
endmodule

module parallel_run_length
#(
    parameter DATA_WIDTH = 8,
    parameter NUM_STREAMS = 4
)
(
    input wire clk,
    input wire reset_n,
    input wire [NUM_STREAMS-1:0] data_in,
    input wire [NUM_STREAMS-1:0] stream_enable,
    output reg [NUM_STREAMS-1:0] data_out,
    output reg [(NUM_STREAMS * ($clog2(DATA_WIDTH)+1)) - 1:0] run_value,
    output reg [NUM_STREAMS-1:0] valid
)

    reg [NUM_STREAMS-1:0] run_length;
    reg [NUM_STREAMS-1:0] prev_data_in;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            run_length <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
            prev_data_in <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
            valid <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
        end
        else begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (data_in[i] == prev_data_in[i]) begin
                        if (run_length[i] == DATA_WIDTH) begin
                            run_value[i] <= run_length[i];
                            run_length[i] <= 1;
                        end else if (run_length[i] < DATA_WIDTH) begin
                            run_length[i] <= run_length[i] + 1;
                        end else begin
                            run_length[i] <= 1;
                        end
                    end else begin
                        run_value[i] <= run_length[i];
                        run_length[i] <= 1;
                    end
                    prev_data_in[i] <= data_in[i];
                end
            end
            valid <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (run_length[i] == DATA_WIDTH || data_in[i] != prev_data_in[i]) begin
                        valid[i] <= 1;
                    end else begin
                        valid[i] <= 0;
                    end
                end
            end
        end
    end

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            data_out <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
            valid <= ( replicate({$clog2(DATA_WIDTH)+1} 0) );
        end
        else begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (run_length[i] == DATA_WIDTH || data_in[i] != prev_data_in[i]) begin
                        data_out[i] <= prev_data_in[i];
                        run_value[i] <= run_length[i];
                    end else begin
                        data_out[i] <= 0;
                        run_value[i] <= 0;
                    end
                end
            end
        end
    end
endmodule

