reg [19-1:0] seed_2 = 19'h12345;
reg [24-1:0] s_sum=0, s_prev=0, s_out=0;
always @ (posedge clk_sig) begin
  if (clk_en_sig) begin
    if (&seed_1)
      seed_1 <= #1 24'h654321;
    else
      seed_1 <= #1 {seed_1[22:0], ~(seed_1[23] ^ seed_1[22] ^ seed_1[21] ^ seed_1[16])};
  end
