output.rtl/sorting_engine.sv:
module sorting_engine (
    input clock,
    input rst,
    input start,
    input [WIDTH-1:0] in_data,
    output [WIDTH-1:0] out_data,
    output done
);

    // State machine states
    state state;
    enum state State = IDLE | SORTING | DONE;

    // State register
    reg state state_state = IDLE;

    // Internal registers
    reg [N*WIDTH-1:0] temp_data = 0;
    reg [N*WIDTH-1:0] sorted_data = 0;
    reg [N*WIDTH-1:0] input_data = 0;
    reg [N*WIDTH-1:0] output_data = 0;
    reg pass = 0;

    // Always blocks
    always @posedge clock begin
        case (state_state)
            IDLE:
                // Initialize on first reset
                if (rst) begin
                    state_state = IDLE;
                    sorted_data = 0;
                    input_data = 0;
                    output_data = 0;
                    pass = 0;
                end
                // Transition to SORTING state when start is asserted
                if (start) begin
                    state_state = SORTING;
                end
            SORTING:
                // Perform bubble sort passes
                if (pass < N*(N-1)) begin
                    // Compare and swap adjacent elements
                    for (int i = 0; i < N-1; i++) begin
                        if (input_data[i] > input_data[i+1]) begin
                            // Swap elements
                            reg [WIDTH-1:0] temp = input_data[i];
                            input_data[i] = input_data[i+1];
                            input_data[i+1] = temp;
                        end
                    end
                    // Decrement pass counter
                    pass = pass + 1;
                end
                // Transition to DONE state after all passes
                if (pass == N*(N-1)) begin
                    state_state = DONE;
                end
            DONE:
                // Output sorted data
                if (rst) begin
                    output_data = 0;
                else
                    output_data = sorted_data;
                end
        default:
            // No action
            state_state = IDLE;
    endcase
endmodule

input.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        j <= 0;
                    end
                end

                SORTING: begin
                    // Perform a single comparison and swap if needed
                    if (val_j > val_j1) begin
                        array[j]   <= val_j1;
                        array[j+1] <= val_j;
                    end

                    // Update j
                    if (j == N-2) begin
                        // One pass completed, increment i
                        j <= 0;
                        i <= i + 1;
                    end else begin
                        j <= j + 1;
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

