module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for insertion sort
    reg [$clog2(N)-1:0] i;  // Current element index
    reg [$clog2(N)-1:0] pos; // Position to insert current element

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;

    assign val_j  = array[i];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Insert current element into sorted subarray
                for (int k = 0; k < i; k = k + 1) begin
                    if (array[k] > val_j) begin
                        array[k+1] <= array[k];
                    end else begin
                        pos <= k;
                        break;
                    end
                end
                array[pos] <= val_j;

                // Update indices
                i <= i + 1;
                if (i == N) begin
                    next_state = DONE;
                end
            end
            DONE: begin
                // Sorting complete
                done <= 1;
                // Output the sorted data
                for (int m = 0; m < N; m = m + 1) begin
                    out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                end
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            pos <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        pos <= 0;
                    end
                end

                SORTING: begin
                    // Perform insertion sort
                    for (int k = 0; k < N; k = k + 1) begin
                        val_j <= array[k];
                        i <= k;
                        while (i > 0 && array[i-1] > val_j) begin
                            array[i] <= array[i-1];
                            i <= i - 1;
                        end
                        array[0] <= val_j;
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    reg [1:0]  state, next_state;
    reg [WIDTH-1:0] data_array [0:N-1];
    reg [3:0]   pass_cnt;
    reg [3:0]   pair_idx;

    wire [3:0] pairs_in_this_pass;

    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (4) : (3 > 0 ? 3 : 0);

    always @posedge rst) begin
        state = IDLE;
    end

    always @posedge start) begin
        if (rst) begin
            state = IDLE;
            data_array = { {0} };
        end else begin
            if (state == IDLE) begin
                state = LOAD;
                data_array = in_data;
            end else if (state == LOAD) begin
                state = SORT;
            end else if (state == SORT) begin
                for (pass_cnt = 0; pass_cnt < N; pass_cnt = pass_cnt + 1) begin
                    pair_idx = 0;
                    if (pass_cnt % 2 == 0) begin
                        for (pair_idx = 0; pair_idx < N/2; pair_idx = pair_idx + 1) begin
                            if (data_array[2*pair_idx] > data_array[2*pair_idx + 1]) begin
                                data_array[2*pair_idx] = data_array[2*pair_idx + 1];
                                data_array[2*pair_idx + 1] = data_array[2*pair_idx];
                            end
                        end
                    else begin
                        for (pair_idx = 0; pair_idx < N/2 - 1; pair_idx = pair_idx + 1) begin
                            if (data_array[2*pair_idx + 1] > data_array[2*pair_idx + 2]) begin
                                data_array[2*pair_idx + 1] = data_array[2*pair_idx + 2];
                                data_array[2*pair_idx + 2] = data_array[2*pair_idx + 1];
                            end
                        end
                    end
                end
                state = DONE;
            end
        end
    end

    always @posedge clock) begin
        if (state == SORT) begin
            pass_cnt = pass_cnt + 1;
        end
    end

    // Output the sorted data
    out_data = data_array;
    done = 1'd0;
endmodule

module sorting_engine #(
    parameter N = 8,
    parameter WIDTH = 8
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    localparam [3:0]
        S_IDLE         = 4'd0,
        S_LOAD_INPUT   = 4'd1,
        S_FIND_MAX     = 4'd2,
        S_COUNT        = 4'd3,
        S_PREFIX_SUM   = 4'd4,
        S_BUILD_OUTPUT = 4'd5,
        S_COPY_OUTPUT  = 4'd6,
        S_DONE         = 4'd7;

    reg [3:0]           current_state;
    reg [WIDTH-1:0]     data_array [0:N-1];
    reg [WIDTH-1:0]     out_array  [0:N-1];
    reg [$clog2(N):0]   count_array[0:(1<<WIDTH)];
    reg [WIDTH-1:0]     max_val;

    always @(*) begin
        case(current_state)
            S_IDLE:
                if (start) begin
                    current_state = S_LOAD_INPUT;
                    data_array = in_data;
                end
                default:
                    current_state = S_IDLE;
                    break;
            S_LOAD_INPUT:
                next_data_array = data_array;
                next_state = S_FIND_MAX;
                next_max_val = 0;
                next_count_array = count_array;
                next_find_cnt = 0;
                next_count_cnt = 0;
                next_build_cnt = 0;
                next_copy_cnt = 0;
                next_done = 0;
                next_out_data = out_data;
                for (i = 0; i < N; i = i + 1) begin
                    count_array[data_array[i]] = count_array[data_array[i]] + 1;
                end
                current_state = S_FIND_MAX;
                break;
            S_FIND_MAX:
                next_data_array = data_array;
                next_state = S_COUNT;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt + 1;
                next_count_cnt = count_cnt;
                next_build_cnt = build_cnt;
                next_copy_cnt = copy_cnt;
                next_done = done;
                next_out_data = out_data;
                max_val = data_array[0];
                for (i = 1; i < N; i = i + 1) begin
                    if (data_array[i] > max_val) begin
                        max_val = data_array[i];
                    end
                end
                current_state = S_COUNT;
                break;
            S_COUNT:
                next_data_array = data_array;
                next_state = S_PREFIX_SUM;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt;
                next_count_cnt = count_cnt + 1;
                next_build_cnt = build_cnt;
                next_copy_cnt = copy_cnt;
                next_done = done;
                next_out_data = out_data;
                for (i = max_val; i > 0; i = i - 1) begin
                    count_array[i] = count_array[i] + count_array[i + 1];
                end
                current_state = S_PREFIX_SUM;
                break;
            S_PREFIX_SUM:
                next_data_array = data_array;
                next_state = S_BUILD_OUTPUT;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt;
                next_count_cnt = count_cnt;
                next_build_cnt = build_cnt + 1;
                next_copy_cnt = copy_cnt;
                next_done = done + 1;
                next_out_data = out_data;
                for (i = N - 1; i >= 0; i = i - 1) begin
                    val = data_array[i];
                    pos = count_array[val];
                    out_array[pos] = val;
                    count_array[val] = count_array[val] - 1;
                end
                current_state = S_BUILD_OUTPUT;
                break;
            S_BUILD_OUTPUT:
                next_data_array = data_array;
                next_state = S_COPY_OUTPUT;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt;
                next_count_cnt = count_cnt;
                next_build_cnt = build_cnt;
                next_copy_cnt = copy_cnt + 1;
                next_done = done;
                next_out_data = out_data;
                for (i = 0; i < N; i = i + 1) begin
                    out_data[i] = out_array[i];
                end
                current_state = S_COPY_OUTPUT;
                break;
            S_COPY_OUTPUT:
                next_data_array = data_array;
                next_state = S_DONE;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt;
                next_count_cnt = count_cnt;
                next_build_cnt = build_cnt;
                next_copy_cnt = copy_cnt;
                next_done = done + 1;
                next_out_data = out_data;
                current_state = S_DONE;
                break;
            S_DONE:
                next_data_array = data_array;
                next_state = S_IDLE;
                next_max_val = max_val;
                next_count_array = count_array;
                next_find_cnt = find_cnt;
                next_count_cnt = count_cnt;
                next_build_cnt = build_cnt;
                next_copy_cnt = copy_cnt;
                next_done = done;
                next_out_data = out_data;
                current_state = S_IDLE;
                break;
        end
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= S_IDLE;
            done          <= 1'b0;
            out_data      <= {N*WIDTH{1'b0}};
            max_val       <= {WIDTH{1'b0}};
            load_cnt      <= 0;
            find_cnt      <= 0;
            count_cnt     <= 0;
            prefix_cnt    <= 0;
            build_cnt     <= 0;
            copy_cnt      <= 0;
            for (i = 0; i < N; i = i + 1) begin
                data_array[i] <= {WIDTH{1'b0}};
                out_array[i]  <= {WIDTH{1'b0}};
            end
            for (i = 0; i < (1<<WIDTH); i = i + 1) begin
                count_array[i] <= {($clog2(N)+1){1'b0}};
            end
        end else begin
            next_state = current_state;
            next_data_array = data_array;
            next_out_array = out_array;
            next_count_array = count_array;
            next_max_val = max_val;
            next_find_cnt = find_cnt;
            next_count_cnt = count_cnt;
            next_build_cnt = build_cnt;
            next_copy_cnt = copy_cnt;
            next_done = done;
            next_out_data = out_data;
        end
    end
endmodule

