`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3,
    parameter clock,
    parameter reset,
    parameter write_en,
    parameter read_en,
    parameter data_in,
    output empty,
    output full,
    output data_out
) {
    parameter depth = 1 << ADDR_WIDTH;
    reg state = 'idle';
    reg ptr = 0;
    reg [DATA_WIDTH-1:0] data_out = 0;
    reg [DATA_WIDTH-1:0] data_in;
    reg [depth-1:0] fifo_array;

    always clock_edge begin
        case (state)
            'idle:
                if (reset) begin
                    empty = 1;
                    full = 1;
                    fifo_array = 0;
                    ptr = 0;
                end else if (write_en) begin
                    if (count(fifo_array) < depth) begin
                        fifo_array[ptr] = data_in;
                        ptr = (ptr + 1) % depth;
                    end
                end else if (read_en) begin
                    if (count(fifo_array) > 0) begin
                        data_out = fifo_array[ptr];
                        ptr = (ptr - 1 + depth) % depth;
                        empty = 0;
                        full = 0;
                    end
                end
                state = 'write';
            'write:
                if (write_en) begin
                    if (count(fifo_array) < depth) begin
                        fifo_array[ptr] = data_in;
                        ptr = (ptr + 1) % depth;
                    end
                end else begin
                    state = 'idle';
                end
            'read:
                if (read_en) begin
                    if (count(fifo_array) > 0) begin
                        data_out = fifo_array[ptr];
                        ptr = (ptr - 1 + depth) % depth;
                        empty = 0;
                        full = 0;
                    end
                end else begin
                    state = 'idle';
                end
            'empty:
                state = 'idle';
            'full:
                state = 'idle';
        endcase
    end
}

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top(
    input clock,
    input reset_n,
    input data_in,
    input sel,
    output serial_out,
    output done,
    output data_out
);

    include "tx_block"
    include "rx_block"

endmodule

module tx_block(
    input clock,
    input reset_n,
    input data_in,
    input sel,
    output serial_out,
    output done,
    output serial_clk
);

    reg [MAX_WIDTH-1:0] data_out;
    reg [MAX_WIDTH-1:0] data_in_reg;
    reg [MAX_WIDTH-1:0] serial_out_reg;
    reg serial_clk_reg;
    reg [15:0] tx_reg;
    reg [15:0] sel_reg;

    always clocked begin
        if (reset_n)
            tx_reg = 0;
            sel_reg = 0;
        else
            sel_reg = sel;
            tx_reg = data_in;

            if (sel_reg[2:0] == 3'h0)
                serial_out_reg = 0;
            else
                integer width = sel_reg[2:0] + 3;
                if (width > MAX_WIDTH)
                    serial_out_reg = 0;
                else
                    serial_out_reg = data_in_reg[(MAX_WIDTH-1):width];

            serial_clk_reg = 1;
        end
    end

    assign serial_out = serial_out_reg;
    assign done = 0;
    assign serial_clk = serial_clk_reg;
endmodule

module rx_block(
    input clock,
    input reset_n,
    input serial_clk,
    input data_in,
    input sel,
    output data_out,
    output done
);

    reg [MAX_WIDTH-1:0] data_out_reg;
    reg [MAX_WIDTH-1:0] data_in_reg;
    reg [15:0] rx_reg;
    reg [15:0] sel_reg;
    reg done_reg;

    always clocked begin
        if (reset_n)
            rx_reg = 0;
            done_reg = 0;
        else
            sel_reg = sel;
            data_in_reg = data_in;

            if (sel_reg[2:0] == 3'h0)
                data_out_reg = 0;
            else
                integer width = sel_reg[2:0] + 3;
                if (width > MAX_WIDTH)
                    data_out_reg = 0;
                else
                    data_out_reg = data_in_reg[(MAX_WIDTH-1):width];

            if (serial_clk)
                rx_reg = data_out_reg;
                done_reg = 1;
            else
                rx_reg = 0;
        end
    end

    assign data_out = data_out_reg;
    assign done = done_reg;
endmodule

