module thermostat (
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_clr,
    input wire i_clk,
    input wire i_rst,
    output reg [2:0] o_state,
    output reg [5:0] o_heater,
    output reg [5:0] o_aircon,
    output reg o_fan
);

    reg current_state = 0;

    always @(posedge i_clk) begin
        if (i_rst) begin
            current_state = 0;
            o_heater = 0;
            o_aircon = 0;
            o_fan = 0;
        elsif (i_fault) begin
            current_state = 0;
            o_heater = 0;
            o_aircon = 0;
            o_fan = 0;
        elsif (i_enable) begin
            current_state = 0;
            o_heater = 0;
            o_aircon = 0;
            o_fan = 0;
        else begin
            case (current_state)
                0: 
                    if (i_full_cold) begin
                        current_state = 3;
                    elsif (i_medium_cold) begin
                        current_state = 2;
                    elsif (i_low_cold) begin
                        current_state = 1;
                    elsif (i_low_hot) begin
                        current_state = 4;
                    elsif (i_medium_hot) begin
                        current_state = 5;
                    elsif (i_full_hot) begin
                        current_state = 6;
                    end else:
                        current_state = 0;
                3: 
                    if (i_full_cold) current_state = 3;
                    else if (i_medium_cold) current_state = 2;
                    else if (i_low_cold) current_state = 1;
                    else current_state = 0;
                2: 
                    if (i_full_cold) current_state = 3;
                    else if (i_medium_cold) current_state = 2;
                    else if (i_low_cold) current_state = 1;
                    else current_state = 0;
                4: 
                    if (i_full_hot) current_state = 6;
                    else if (i_medium_hot) current_state = 5;
                    else if (i_low_hot) current_state = 4;
                    else current_state = 0;
                5: 
                    if (i_full_hot) current_state = 6;
                    else if (i_medium_hot) current_state = 5;
                    else if (i_low_hot) current_state = 4;
                    else current_state = 0;
                6: 
                    if (i_full_hot) current_state = 6;
                    else if (i_medium_hot) current_state = 5;
                    else if (i_low_hot) current_state = 4;
                    else current_state = 0;
                default: current_state = 0;
            end case
        end
    end

    // Set outputs based on state and inputs
    o_state = current_state;
    o_heater[5] = (current_state & 0x100) ? 1 : 0;
    o_heater[4] = (current_state & 0x080) ? 1 : 0;
    o_heater[3] = (current_state & 0x040) ? 1 : 0;
    o_aircon[5] = (current_state & 0x100) ? 0 : 0;
    o_aircon[4] = (current_state & 0x080) ? 0 : 0;
    o_aircon[3] = (current_state & 0x040) ? 0 : 0;
    o_fan = (current_state & 0x008) ? 1 : 0;
    o_fan |= i_fan_on;
endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
    input clock,
    input reset,
    input axi_addr,
    input axi_wdata,
    input axi_write_en,
    input axi_read_en
    output axi_rdata
);

    // Registers
    reg [31:0] count; // 32-bit counter (lower 16 bits used)
    reg [31:0] match_value; // Match value register
    reg [31:0] reload_value; // Reload value register
    reg [31:0] control; // Control bits (enable, interval_mode, interrupt_enable)
    reg [31:0] status; // Status register (interrupt flag)

    // Constants
    const MATCH_WIDTH = 16;
    const RELOAD_WIDTH = 16;

    // Address mapping
    reg [31:0] count_addr = 0x0;
    reg [31:0] match_addr = 0x1;
    reg [31:0] reload_addr = 0x2;
    reg [31:0] control_addr = 0x3;
    reg [31:0] status_addr = 0x4;

    // Logic
    always clocked begin
        if (reset) begin
            count = 0;
            match_value = 0;
            reload_value = 0;
            control = 0b000;
            status = 0;
        end else begin
            if (axi_write_en) begin
                // Write to registers
                count[count_addr] = axi_wdata;
                match_value[match_addr] = axi_wdata;
                reload_value[reload_addr] = axi_wdata;
                control[control_addr] = axi_wdata;
            end

            // Counter increment
            if (axi_read_en) begin
                count[count_addr] = (count[count_addr] + 1) & 0xFFFF;
            end

            // Match detection
            if (count[count_addr] == match_value[match_addr]) begin
                if (axi_write_en) begin
                    reload_value[reload_addr] = axi_wdata;
                end
                status = 1;
            end

            // Interrupt handling
            if (axi_read_en && (status == 1)) begin
                if (control[3:2] == 1) begin
                    if (axi_write_en) begin
                        status[status_addr] = 0;
                    end
                end
            end
        end
    end

    // AXI-Lite ports
    axi_rdata = count[count_addr];
endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot(
    input [255:0] source_reg,
    input sign,
    input size,
    input [2:0] one_hot_selector,
    output [511:0] destination_reg
);

    // Initialize destination register
    destination_reg = 0;

    // Determine chunk size based on one-hot selector
    integer chunk_size;
    case (one_hot_selector)
        3'b000: chunk_size = 256; // Default case: no unpacking
        3'b001: chunk_size = 1;
        3'b010: chunk_size = 2;
        3'b100: chunk_size = size ? 8 : 4;
    endcase

    // Loop through source register in chunks
    for (int i = 0; i < 256; i += chunk_size) begin
        // Extract chunk from source register
        bit [7:0] chunk = source_reg[i + 7: i];

        // Convert chunk to signed or unsigned value
        if (sign) begin
            if (chunk & 128) begin // Negative number
                chunk = (chunk + 128) * 8;
            else
                chunk = chunk * 8;
            end
        else
            chunk = chunk * 8;
        end

        // Write chunk to destination register
        destination_reg[i + 7: i] = chunk;
    endfor

endmodule

