module vga_controller(
    input clock,
    input reset,
    input color_in,
    output hsync,
    output vsync,
    output [7:0] red, green, blue,
    output [9:0] next_x, next_y
);

    // Horizontal State Machine
    state h_state = h_state_initial;
    reg h_state_state = h_state_initial;

    state v_state = v_state_initial;
    reg v_state_state = v_state_initial;

    // Counters
    reg h_counter = 0;
    reg v_counter = 0;

    // Color Control
    reg [7:0] color_red = 0;
    reg [7:0] color_green = 0;
    reg [7:0] color_blue = 0;

    // State Transitions
    always_edge clock begin
        case (h_state_state)
            h_state_initial: 
                h_counter = 0;
                v_counter = 0;
                h_state = h_active;
                v_state = v_active;
                blank = 0;
                line_done = 0;
                vsync = 1;
                vsync = 0;
            h_active:
                h_counter = h_counter + 1;
                if (h_counter == h_active) h_counter = 0;
                if (h_counter == h_front) begin
                    hsync = 1;
                    h_state = h_front porch;
                    vsync = 0;
                end else if (h_counter == h_pulse) begin
                    hsync = 0;
                    h_state = h_back porch;
                    vsync = 0;
                end else if (h_counter == h_back) h_state = h_active;
            h_front porch:
                h_counter = h_counter + 1;
                if (h_counter == h_back) begin
                    hsync = 0;
                    h_state = h_back porch;
                    vsync = 0;
                else vsync = 1;
                vsync = 0;
                h_counter = h_counter + 1;
                if (h_counter == h_active) h_state = h_active;
            h_back porch:
                h_counter = h_counter + 1;
                if (h_counter == h_active) h_state = h_active;
                vsync = 1;
        endcase

        case (v_state_state)
            v_state_initial:
                v_counter = 0;
                v_state = v_active;
                vsync = 1;
                line_done = 0;
                blank = 0;
            v_active:
                v_counter = v_counter + 1;
                if (v_counter == v_active) v_counter = 0;
                if (v_counter == v_front) v_state = v_front porch;
                else if (v_counter == v_pulse) begin
                    vsync = 0;
                    v_state = v_back porch;
                    line_done = 1;
                end else if (v_counter == v_back) v_state = v_active;
            v_front porch:
                v_counter = v_counter + 1;
                if (v_counter == v_back) begin
                    vsync = 0;
                    v_state = v_back porch;
                    line_done = 1;
                else line_done = 0;
                v_counter = v_counter + 1;
                if (v_counter == v_active) v_state = v_active;
            v_back porch:
                v_counter = v_counter + 1;
                if (v_counter == v_active) v_state = v_active;
                vsync = 1;
        endcase
    end

    // Color Control Logic
    always h_state_state, v_state_state, h_counter, v_counter begin
        if (h_state_state == h_active || v_state_state == v_active) begin
            if (color_in[7:5]) red = 128;
            else red = 0;
            if (color_in[4:2]) green = 128;
            else green = 0;
            if (color_in[1:0]) blue = 128;
            else blue = 0;
        else begin
            red = 0;
            green = 0;
            blue = 0;
        end
    end

    // Blank Signal
    blank = hsync & vsync;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

    // Synchronous Output Signals
    hsync = 1;
    vsync = 1;
    blank = 0;

endmodule

module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,      // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state, // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                    while (h_counter < H_ACTIVE - 1) begin
                        h_counter <= h_counter + 1;
                        hsync <= HIGH;
                    end
                    h_state <= H_FRONT_STATE;
                end
                H_FRONT_STATE: begin
                    while (h_counter < H_FRONT - 1) begin
                        h_counter <= h_counter + 1;
                        hsync <= HIGH;
                    end
                    h_state <= H_PULSE_STATE;
                end
                H_PULSE_STATE: begin
                    hsync <= LOW;
                    while (h_counter < H_PULSE - 1) begin
                        h_counter <= h_counter + 1;
                    end
                    h_state <= H_BACK_STATE;
                end
                H_BACK_STATE: begin
                    hsync <= HIGH;
                    while (h_counter < H_BACK - 1) begin
                        h_counter <= h_counter + 1;
                    end
                    h_state <= H_ACTIVE_STATE;
                    line_done <= HIGH;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    while (v_counter < V_ACTIVE - 1) begin
                        v_counter <= v_counter + 1;
                        vsync <= HIGH;
                    end
                    v_state <= V_FRONT_STATE;
                end
                V_FRONT_STATE: begin
                    while (v_counter < V_FRONT - 1) begin
                        v_counter <= v_counter + 1;
                        vsync <= HIGH;
                    end
                    v_state <= V_PULSE_STATE;
                end
                V_PULSE_STATE: begin
                    vsync <= LOW;
                    while (v_counter < V_PULSE - 1) begin
                        v_counter <= v_counter + 1;
                    end
                    v_state <= V_BACK_STATE;
                end
                V_BACK_STATE: begin
                    vsync <= HIGH;
                    while (v_counter < V_BACK - 1) begin
                        v_counter <= v_counter + 1;
                    end
                    v_state <= V_ACTIVE_STATE;
                end
            endcase
        end
    end


    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync_reg & vsync_reg;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

