module virtual2physical_tlb #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, TLB_SIZE = 4, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    output [PAGE_WIDTH-1:0] physical_address,
    output hit, miss
);
    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;
    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );
endmodule

module TLB #(parameter TLB_SIZE = 4, ADDR_WIDTH = 8, PAGE_WIDTH = 8) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    input tlb_write_enable,
    input flush,
    input [PAGE_WIDTH-1:0] page_table_entry,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg hit,
    output reg miss
);
    // TLB Storage
    reg [ADDR_WIDTH-1:0] virtual_tags[TLB_SIZE-1:0];
    reg [PAGE_WIDTH-1:0] physical_pages[TLB_SIZE-1:0];
    reg [TLB_SIZE-1:0] valid_bits;
    reg [$clog2(TLB_SIZE)-1:0] replacement_index; // Index for the next replacement
    integer i;

    // Insert the logic here to update TLB with a new page table entry using the replacement policy
    always_comb begin
        hit = 0;
        miss = 1;
        physical_address = 0;

        // Check for a match in TLB
        for (i = 0; i < TLB_SIZE; i = i + 1) begin
            if (virtual_address == (virtual_tags[i] << PAGE_WIDTH)) begin
                hit = 1;
                physical_address = physical_pages[i];
                break;
            end
        end
    end
endmodule

module PageTableHandler #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input miss,
    input [ADDR_WIDTH-1:0] virtual_page,
    output reg [PAGE_WIDTH-1:0] page_table_entry,
    output reg ready
);
    // Parameterized Page Table Memory
    reg [PAGE_WIDTH-1:0] page_table_memory [0:PAGE_TABLE_SIZE-1];
 assign   page_table_entry = page_table_memory[virtual_page];  
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Initialize Page Table Memory during reset
            page_table_memory[0] <= 8'h0;
            page_table_memory[1] <= 8'h1;
            page_table_memory[2] <= 8'h2;
            page_table_memory[3] <= 8'h3;  
            page_table_memory[4] <= 8'h4;
            page_table_memory[5] <= 8'h5;
            page_table_memory[6] <= 8'h6;
            page_table_memory[7] <= 8'h7;
            page_table_memory[8] <= 8'h8;  
            page_table_memory[9] <= 8'h9;
            page_table_memory[10] <= 8'hA;
            page_table_memory[11] <= 8'hB;  
            page_table_memory[12] <= 8'hC;
            page_table_memory[13] <= 8'hD;
            page_table_memory[14] <= 8'hE;
            page_table_memory[15] <= 8'hF;          
            ready <= 0;
        end else if (miss) begin
            // Fetch the physical page number from the simulated page table         
            ready <= 1; // Indicate the entry is ready
        end else begin
            ready <= 0;
        end
    end
endmodule

module ControlUnit (
    input clk,
    input reset,
    input hit,
    input miss,
    input ready,
    output reg tlb_write_enable,
    output reg flush
);
    reg [1:0] state;

    localparam IDLE = 2'b00,
               FETCH = 2'b01,
               UPDATE = 2'b10;

    always begin
        if (reset) begin
            state = IDLE;
            tlb_write_enable = 0;
            flush = 0;
        end else if (hit) begin
            state = FETCH;
            tlb_write_enable = 0;
            flush = 0;
        end else if (miss) begin
            state = UPDATE;
            tlb_write_enable = 1;
            flush = 0;
        end else begin
            state = IDLE;
            tlb_write_enable = 0;
            flush = 0;
        end
    end

    // Handle write operation
    always @posedge clock or posedge reset) begin
        case (state)
            IDLE, FETCH: 
                // Do nothing
                break;
            UPDATE: 
                // Enable TLB write
                tlb_write_enable = 1;
                // Check if flush is requested
                if (flush) begin
                    // Flush the TLB
                    valid_bits = 0;
                    replacement_index = 3;
                    tlb_write_enable = 0;
                end
                // Transition back to IDLE
                state = IDLE;
                break;
        endcase
    end
endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge(
    input wire [31:0] addr_i,
    input wire [31:0] data_i,
    input wire [3:0] sel_i,
    input wire rst_i,
    input wire cyc_i,
    input wire stb_i,
    input wire we_i,
    output wire [31:0] data_o,
    output wire ack_o,
    output wire [1:0] htrans,
    output wire [2:0] hsize,
    output wire [2:0] hburst,
    output wire haddr,
    output wire hwdata
);

    // FSM states
    enum state { IDLE, NON-SEQUENTIAL, BUSY };
    reg state = IDLE;

    // Address and data buffers
    reg [31:0] ahb_addr;
    reg [31:0] ahb_data;
    reg [31:0] ahb_data_o;

    // Transaction control
    reg [2:0] hsize_val = 0;
    reg [1:0] htrans_val = 0;
    reg [1:0] hburst_val = 0;

    // Data conversion
    wire [31:0] temp_data;
    wire [31:0] temp_addr;

    // State transitions
    always @(posedge rst_i or posedge hreset_n) begin
        if (rst_i || hreset_n) begin
            state = IDLE;
            ahb_addr = 0;
            ahb_data = 0;
            ahb_data_o = 0;
            hsize_val = 0;
            htrans_val = 0;
            hburst_val = 0;
        end
    end

    // Address calculation
    always begin
        case (sel_i[3])
            1: ahb_addr = addr_i;
            2: ahb_addr = (addr_i >> 2);
            3: ahb_addr = (addr_i >> 4);
            default: ahb_addr = 0;
        endcase
    end

    // Data conversion
    always begin
        case (sel_i[3])
            1: ahb_data = data_i;
            2: ahb_data = (data_i >> 2);
            3: ahb_data = (data_i >> 4);
            default: ahb_data = 0;
        endcase
    end

    // Data handling
    always begin
        if (stb_i && cyc_i) begin
            if (state == IDLE) begin
                state = NON-SEQUENTIAL;
                haddr = ahb_addr;
                hwdata = ahb_data;
                hsize_val = sel_i[2];
                htrans_val = sel_i[1];
                hburst_val = 0;
            end else if (state == NON-SEQUENTIAL) begin
                if (hready) begin
                    state = BUSY;
                    ack_o = 1;
                    htrans = 3'b000;
                    hsize = 3'h000;
                    hburst = 3'h000;
                end
            end else if (state == BUSY) begin
                if (hready) begin
                    state = IDLE;
                    ack_o = 0;
                    htrans = 3'b000;
                    hsize = 3'h000;
                    hburst = 3'h000;
                end
            end
        end
    end

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;

    reg [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;
    reg                  match_detected;

